INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (195, 1, NULL, NULL, 39, 'Artist Management', 'artist-management-en-us', NULL, 'We collaborate with brands and special projects by connecting the right name to communicate with the desired audience. Additionally, we work alongside influencers and celebrities in developing tailored content for each talent, stitching partnerships and opportunities together.', 'published', '{"order":5,"language":"enUS","videos":null,"fichaTecnica":[],"socialMedia":null,"posttype":"servicos","legacy_id":"b026f66b-0bdf-4181-9be6-f0ecb9f3d6b0","legacy_posttype":"tiposervicos"}', 1716338204107, 1716338204107, 1716338204107);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (196, 1, NULL, NULL, 39, 'Creation and Scriptwriting', 'creation-and-scriptwriting-en-us', NULL, 'Farra''s scriptwriting room is composed of diverse and versatile professionals to cater to a wide range of genres and formats, from a fiction drama to a non-fiction reality show, from a social media video to a branded content series.', 'published', '{"order":2,"language":"enUS","videos":null,"fichaTecnica":[],"socialMedia":null,"posttype":"servicos","legacy_id":"3f91be34-2af3-416a-97d6-036631b496da","legacy_posttype":"tiposervicos"}', 1716338368520, 1716338368520, 1716338368520);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (197, 1, NULL, NULL, 41, 'Criação e Roteiro', 'criacao-e-roteiro-pt-br', NULL, 'A sala de roteiro da Farra é formada por profissionais diversos e versáteis para atender a um amplo número de gêneros e formatos, de um drama de ficção a um reality show de não-ficção, de um vídeo para social media a uma série de branded content.', 'published', '{"order":2,"language":"ptbr","videos":null,"fichaTecnica":[],"socialMedia":null,"posttype":"servicos","legacy_id":"bc9678a1-c3c4-468c-b826-8378b795f36f","legacy_posttype":"tiposervicos"}', 1716338112400, 1716338112400, 1716338112400);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (198, 1, NULL, NULL, 41, 'Estratégia', 'estrategia-pt-br', NULL, 'Planejamento estratégico para criação de campanhas e projetos especiais de branded content e entertainment.', 'published', '{"order":6,"language":"ptbr","videos":null,"fichaTecnica":[],"socialMedia":null,"posttype":"servicos","legacy_id":"c8d31181-4628-4b93-ace9-f80fe147d20f","legacy_posttype":"tiposervicos"}', 1716338104607, 1716338104607, 1716338104607);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (199, 1, NULL, NULL, 41, 'Mídias Sociais', 'midias-sociais-pt-br', NULL, 'Planejamento, criação de conteúdo, gerenciamento de postagens e análise de resultados para canais, perfis e páginas.', 'published', '{"order":4,"language":"ptbr","videos":null,"fichaTecnica":[],"socialMedia":null,"posttype":"servicos","legacy_id":"6ae23b67-6610-4780-b53c-908d0b332b05","legacy_posttype":"tiposervicos"}', 1716338081044, 1716338081044, 1716338081044);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (200, 1, NULL, NULL, 39, 'Post-production', 'post-production-en-us', NULL, 'Farra''s post-production team consists of specialists prepared to handle all stages: editing, motion graphics (animations), sound design, and color grading.', 'published', '{"order":3,"language":"enUS","videos":null,"fichaTecnica":[],"socialMedia":null,"posttype":"servicos","legacy_id":"19a1790a-6bc8-4bb9-b75f-8f02156fc5a8","legacy_posttype":"tiposervicos"}', 1716338351001, 1716338351001, 1716338351001);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (201, 1, NULL, NULL, 39, 'Production', 'production-en-us', NULL, 'Versatile and intelligent production service, ready to operate in a lightweight, efficient, agile, and high-volume manner, with a full understanding of digital demands and in synergy with creative demands.', 'published', '{"order":1,"language":"enUS","videos":null,"fichaTecnica":[],"socialMedia":null,"posttype":"servicos","legacy_id":"f49cdf63-54b4-4215-94c6-82d1f0553e52","legacy_posttype":"tiposervicos"}', 1716338434727, 1716338434727, 1716338434727);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (202, 1, NULL, NULL, 41, 'Produção', 'producao-pt-br', NULL, 'Serviço de produção versátil e inteligente, preparado para atuar de forma leve, eficiente, ágil e volumosa, com compreensão total das demandas digitais e em sinergia com as demandas criativas.', 'published', '{"order":1,"language":"ptbr","videos":null,"fichaTecnica":[],"socialMedia":null,"posttype":"servicos","legacy_id":"b09ce844-3f75-481e-9fe0-9eb25f06125e","legacy_posttype":"tiposervicos"}', 1716338178619, 1716338178619, 1716338178619);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (203, 1, NULL, NULL, 41, 'Produção Artística', 'producao-artistica-pt-br', NULL, 'Colaboramos com marcas e projetos especiais conectando o nome certo para falar com o público desejado. Além disso, atuamos junto a influenciadores e celebridades no desenvolvimento de conteúdos direcionados para cada talento, costurando parcerias e oportunidades. ', 'published', '{"order":5,"language":"ptbr","videos":null,"fichaTecnica":[],"socialMedia":null,"posttype":"servicos","legacy_id":"edd68797-d5c6-4625-a490-c84da9511099","legacy_posttype":"tiposervicos"}', 1716338072223, 1716338072223, 1716338072223);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (204, 1, NULL, NULL, 41, 'Pós-Produção', 'pos-producao-pt-br', NULL, 'A equipe de pós-produção da Farra conta com especialistas preparados para atender a todas as etapas: montagem (edição), motion graphic (animações), sonorização e tratamento de cor.', 'published', '{"order":3,"language":"ptbr","videos":null,"fichaTecnica":[],"socialMedia":null,"posttype":"servicos","legacy_id":"14c6c6db-a667-4724-bf02-c41675883d26","legacy_posttype":"tiposervicos"}', 1716338094051, 1716338094051, 1716338094051);
