INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (206, 1, NULL, NULL, 39, 'Strategy', 'strategy-en-us', NULL, 'Strategic planning for the creation of campaigns and special projects in branded content and entertainment.', 'published', '{"order":6,"language":"enUS","videos":null,"fichaTecnica":[],"socialMedia":null,"posttype":"servicos","legacy_id":"5eef7592-8700-4350-9b6d-326bfbb631e9","legacy_posttype":"tiposervicos"}', 1716338360188, 1716338360188, 1716338360188);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (207, 2, NULL, NULL, 41, 'Serviços', 'servicos-pt-br', NULL, 'Estamos preparados para atender todas as etapas de um projeto audiovisual, desde a sua criação até a entrega final, além de também oferecermos serviços fragmentados para atender a demandas específicas. Podemos, por exemplo, cuidar apenas da criação, apenas do roteiro, apenas da produção ou apenas da pós-produção.', 'published', '{"order":0,"language":"ptbr","videos":null,"fichaTecnica":[],"socialMedia":null,"posttype":"servicos","legacy_id":"bfbc93a6-085d-49bf-9a0e-8c6bf15a258b","legacy_posttype":"servicos"}', 1716338064383, 1716338064383, 1716338064383);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (208, 2, NULL, NULL, 39, 'Services', 'services-en-us', NULL, 'We are prepared to handle all stages of an audiovisual project, from its inception to final delivery, as well as offering fragmented services to meet specific demands. For example, we can take care of only the creation, only the screenplay, only the production, or only the post-production.', 'published', '{"order":0,"language":"enUS","videos":null,"fichaTecnica":[],"socialMedia":null,"posttype":"servicos","legacy_id":"ef621f9b-1f8e-47e5-8310-888b0fbfd51e","legacy_posttype":"servicos"}', 1716338449099, 1716338449099, 1716338449099);
