INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (233, 2, NULL, NULL, 41, 'Quem Somos', 'quem-somos', NULL, 'Os sócios André Brandt, Gui Vieira e Gui Cintra acumulam experiências em roteiro, criação, direção, produção e produção executiva de conteúdo e publicidade nos mais renomados players do mercado, como TV Globo, Netflix, Disney, Instagram, Viacom, WarnerBros Discovery, Spotify, RecordTV, Bandeirantes, Globoplay, Amazon Prime Video, ESPN, GNT e Multishow. Soma-se a essa bagagem um time fixo de profissionais de ofícios plurais, garantindo à Farra a entrega de serviços na lógica end-to-end.', 'published', '{"order":0,"image":"https://bucket.farra.media/banner_quemsomos_desktop_prbr.avif","images":"[\"https://bucket.farra.media/banner_site_quem-somos_mobile-pt.avif\"]","language":"ptbr","videos":null,"videosHome":null,"fichaTecnica":[],"socialMedia":null,"reel":null,"posttype":"quemsomos","legacy_id":"0e199125-242f-45d0-8096-a6defaefd022","legacy_posttype":"quemsomos","post_thumbnail_id":"231"}', 1716340209000, 1716340209000, 1722431412905);
