INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (254, 1, NULL, 'fs9SN8qiF2JCfORn2tkWj3DTiA9qHVhe', 39, 'Gui Cintra', 'gui-cintra-en-us', 'Born in Franca, in the interior of São Paulo, Gui Cintra is a creative producer, screenwriter, director, and format creator, graduated from ECA-USP and the International Film Academy. A partner at Farra, he works creating, developing, producing, and', '<p>Born in Franca, in the interior of São Paulo, Gui Cintra is a creative producer, screenwriter, director, and format creator, graduated from ECA-USP and the International Film Academy. A partner at Farra, he works creating, developing, producing, and directing fiction projects and formats for TV, film, and streaming platforms – on platforms such as TV Globo, Netflix, Disney, HBO, and Paramount. He is the creator of the original idea and screenwriter of the fiction series "B.O." (Netflix), creator of the story and screenwriter of the feature film "Vidente por Acidente" (Disney), development supervisor and producer of the documentary series "Pílulas de Farinha: O Escândalo que Gerou Vidas" (HBO), creator and general director of the comedy show "Do Que Riem?" (Comedy Central).</p><p></p>', 'published', '{"order":"1","image":"https://bucket.farra.media/cintra.avif","language":"enUS","videos":"1e56330a-f375-4fbd-bcfc-b9a26bc32589","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[],"socialMedia":["https://www.linkedin.com/in/guicintra","https://www.instagram.com/cintra/","https://twitter.com/guicintra"],"reel":"d56ca7fb-4d41-433a-ad59-6bcec3e7eeed","posttype":"equipe","legacy_id":"77af8382-14b4-4e1e-af9f-7defee619c6a","legacy_posttype":"equipe","post_thumbnail_id":"289","dono":"sim"}', 1726602973000, 1726602973000, 1779712336497);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (255, 6, NULL, NULL, NULL, 'cintra.avif', 'attachment-equipe-gui-cintra-pt-br', NULL, NULL, 'published', '{"show_in_menu":false,"menu_options":[],"icon":"line-md:file","mime_type":"image/avif","attachment_file":"cintra.avif","attachment_path":"https://bucket.farra.media/cintra.avif","attachment_alt":"Gui Cintra"}', NULL, 1716342389000, 1721171508384);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (256, 1, NULL, 'fs9SN8qiF2JCfORn2tkWj3DTiA9qHVhe', 41, 'Gui Cintra', 'gui-cintra-pt-br', 'Nascido em Franca, interior de São Paulo, Gui Cintra é produtor criativo, roteirista, diretor e criador de formatos, formado pela ECA-USP e pela Academia Internacional de Cinema. Sócio da Farra, atua criando, desenvolvendo, produzindo e dirigindo pro', '<p>Nascido em Franca, interior de São Paulo, Gui Cintra é produtor criativo, roteirista, diretor e criador de formatos, formado pela ECA-USP e pela Academia Internacional de Cinema. Sócio da Farra, atua criando, desenvolvendo, produzindo e dirigindo projetos de ficção e formatos para TV, cinema e streamings – em players como TV Globo, Netflix, Disney, HBO e Paramount. É criador da ideia original e roteirista da série de ficção “B.O.” (Netflix), criador do argumento e roteirista do longa-metragem de ficção “Vidente por Acidente” (Disney), supervisor de desenvolvimento e produtor da série documental “Pílulas de Farinha: O Escândalo que Gerou Vidas” (HBO), criador e diretor geral do humorístico “Do Que Riem?” (Comedy Central / Paramount+), colaborador de roteiro da série de ficção “Desejos S.A.” (Disney), diretor geral do humorístico “Aberto Ao Público” (TV Globo) e criador do reality show “Sua Mãe Te Conhece?” (Netflix). Também atua no mercado publicitário, assinando a criação e direção de campanhas e projetos de branded content para marcas de diversos segmentos – como Nestlé, TIM, Disney, TikTok, C&amp;A, Shoptime e Natura.</p><p></p>', 'published', '{"order":1,"image":"https://bucket.farra.media/cintra.avif","language":"ptbr","videos":"1e56330a-f375-4fbd-bcfc-b9a26bc32589","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[],"socialMedia":["https://www.linkedin.com/in/guicintra","https://www.instagram.com/cintra/","https://twitter.com/guicintra"],"reel":"d56ca7fb-4d41-433a-ad59-6bcec3e7eeed","posttype":"equipe","legacy_id":"a0ae5b15-339a-477a-befb-4989e2381336","legacy_posttype":"equipe","images":"[\"https://bucket.farra.media/bg-o-que-fazemos11.webp\"]","post_thumbnail_id":"290","dono":"sim"}', 1716342389000, 1716342389000, 1779472827592);
