INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (292, 1, NULL, NULL, 39, 'Hugo Moura', 'hugo-moura-en-us', NULL, 'Born in Salvador, Bahia, Hugo Moura is a director, publicist, photographer, and actor. He has lived in Rio de Janeiro for 10 years, where he graduated from the Academia Internacional de Cinema (AIC). With over 800 commercials under his belt, he has created campaigns for major brands such as Coca-Cola, Nivea, Loreal, Uber, among others. Hugo specializes in advertising and fashion films, with a keen eye for photography and aesthetic appeal. He has experience filming with major media personalities, and is a well-rounded director in casting, due to his acting experience, and in his photography skills.', 'published', '{"order":0,"image":"https://bucket.farra.media/jpeg-optimizer_sk_farra_final_029.jpg","language":"enUS","slug":"hugo-moura","videos":"3bafc853-df4f-4193-97e9-c59cc95cdb41","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[],"socialMedia":["https://vimeo.com/dirhugomoura","https://www.imdb.com/name/nm8122831","https://www.instagram.com/hugomourag"],"reel":"3bafc853-df4f-4193-97e9-c59cc95cdb41","posttype":"diretores","legacy_id":"0d85a34d-d056-454f-a657-a9707b7d4213","legacy_posttype":"diretores","images":"[\"https://bucket.farra.media/hugo-moura.png\"]","post_thumbnail_id":"291"}', 1722380215000, 1722380215000, 1727188595248);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (293, 6, NULL, NULL, NULL, 'jpeg-optimizer_sk_farra_final_029.jpg', 'attachment-diretores-hugo-moura-pt-br', NULL, NULL, 'published', '{"show_in_menu":false,"menu_options":[],"icon":"line-md:file","mime_type":"image/jpeg","attachment_file":"jpeg-optimizer_sk_farra_final_029.jpg","attachment_path":"https://bucket.farra.media/jpeg-optimizer_sk_farra_final_029.jpg","attachment_alt":"Hugo Moura"}', NULL, 1721090136000, 1727188622574);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (294, 1, NULL, NULL, 41, 'Hugo Moura', 'hugo-moura-pt-br', NULL, 'Baiano de Salvador, Hugo Moura é diretor, publicitário e de fotografia, e ator. Mora há 10 anos no Rio de Janeiro, onde formou-se pela Academia Internacional de Cinema (AIC). Com mais de 800 filmes publicitários no currículo, assinou campanhas para grandes marcas como Coca-Cola, Nivea, Loreal, Uber, entre outras. Hugo é especialista em publicidade e fashion films, com grande olhar fotográfico e apelo estético. Tem experiência em filmar com grandes personalidades da mídia, um diretor completo na direção de elenco, pela sua bagagem de ator, e no apelo fotográfico.', 'published', '{"order":0,"image":"https://bucket.farra.media/jpeg-optimizer_sk_farra_final_029.jpg","language":"ptbr","slug":"hugo-moura","videos":"3bafc853-df4f-4193-97e9-c59cc95cdb41","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[],"socialMedia":["https://vimeo.com/dirhugomoura","https://www.imdb.com/name/nm8122831","https://www.instagram.com/hugomourag"],"reel":"3bafc853-df4f-4193-97e9-c59cc95cdb41","posttype":"diretores","legacy_id":"82f475bc-6dfe-4989-b975-f31bf1c352fa","legacy_posttype":"diretores","images":"[\"https://bucket.farra.media/MOSAICO TRABALHOS HUGO MOURA v3.png\"]","post_thumbnail_id":"293"}', 1721090136000, 1721090136000, 1727188622574);
