INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (298, 15, NULL, NULL, 41, '#ChegadeEstigma | Intimus / KOTEX', 'chegadeestigma-intimus-kotex-pt-br', NULL, 'Campanha global para a marca Kotex (Intimus no Brasil). Projeto com três etapas, filme hero com o mote da campanha #chegadestigma, ação da Caixa do Estigma na Avenida Paulista e três talk-shows para três países diferentes.', 'published', '{"order":5,"image":"https://bucket.farra.media/inti-1.png","language":"ptbr","slug":"chegadeestigma-intimus-kotex","videos":["https://vimeo.com/589433866","https://vimeo.com/589430298","https://vimeo.com/589430583"],"videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Coord. Produ\u00e7\u00e3o","content":"Guilherme Vieira"},{"title":"Produ\u00e7\u00e3o","content":"Awake Film"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"a0acd772-c27f-44a1-b256-7bf324d2a9c1","legacy_posttype":"jobs","images":"[\"https://bucket.farra.media/maxresdefault-4.jpg\",\"https://bucket.farra.media/caixa_do_estigma_intimus.jpg\",\"https://bucket.farra.media/INTIMUS_FRAME-CAMPANHA-1600x465-1.png\"]","post_thumbnail_id":"297"}', 1716419431000, 1716419431000, 1727312655204);
