INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (300, 15, NULL, NULL, 39, '#LEGADO | Cannabis Thinking', 'legado-cannabis-thinking-en-us', NULL, 'The Green Hub’s team sought us to broadcast the Cannabis Thinking 2022 event. We were responsible for the streaming, production, cameras, sign language and real time translation, graphic packaging and live GC.', 'published', '{"order":58,"image":"https://bucket.farra.media/canna.png","language":"enUS","slug":"legado-cannabis-thinking","videos":"https://vimeo.com/765892192","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Production","content":"Farra"},{"title":"Executive Production","content":"Gui Vieira"},{"title":"Production Manager","content":"Victoria Rodrigues"},{"title":"Editor","content":"Jennifer Brito"},{"title":"Design","content":"Beatriz Vidal e Angelo Ramos"},{"title":"Post Production","content":"Fred Kesselring"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"62cedd64-9d53-4583-9231-7c3b3a770c4d","legacy_posttype":"jobs","post_thumbnail_id":"299"}', 1719708218000, 1719708218000, 1727794808182);
