INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (302, 15, NULL, NULL, 41, '#LEGADO | Cannabis Thinking', 'legado-cannabis-thinking-pt-br', NULL, 'Fomos procurados pelo time da The Green Hub para fazer a transmissão do evento Cannabis Thinking 2022. Organizamos todo o streaming, produção, câmeras, gestão de libras e tradução simultânea, além do pacote gráfico e informações nos GCs da transmissão.Produzimos as fotografias do evento e de convidados.E para Social Media, criamos e roteirizamos algumas editorias e fizemos perguntas aos convidados com uma câmera solta ao evento. Todos esse conteúdo foi edito pós evento e virou conteúdo diário para as redes sociais pelos próximos 3 meses pós evento.', 'published', '{"order":59,"image":"https://bucket.farra.media/canna.png","language":"ptbr","slug":"legado-cannabis-thinking","videos":"https://vimeo.com/765892192","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Produ\u00e7\u00e3o","content":"Farra"},{"title":"Produ\u00e7\u00e3o Executiva","content":"Gui Vieira"},{"title":"Gest\u00e3o de Projetos","content":"Victoria Rodrigues"},{"title":"Edi\u00e7\u00e3o","content":"Jennifer Brito"},{"title":"Design e Arte","content":"Beatriz Vidal e Angelo Ramos"},{"title":"P\u00f3s-produ\u00e7\u00e3o","content":"Fred Kesselring"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"e4557282-867a-4865-95fd-43d9555aee64","legacy_posttype":"jobs","post_thumbnail_id":"301"}', 1716423515000, 1716423515000, 1727186067507);
