INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (304, 15, NULL, NULL, 39, '#LogitechnaBGS | Logitech', 'logitechnabgs-logitech-en-us', NULL, 'Logitech set up a mega stand at Brazil Game Show and recruited Farra to develop the script of the seven day event at the stand. We wrote interviews and content for the whole stand’s presentation and for the hosts, Camilota and Twana.', 'published', '{"order":39,"image":"https://bucket.farra.media/logi.png","language":"enUS","slug":"logitechnabgs-logitech","videos":"https://vimeo.com/765729820","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Writing:","content":"Gui Cintra, Ste Marques"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"7e147ef3-df18-4819-bf7c-5a49f4138530","legacy_posttype":"jobs","post_thumbnail_id":"303"}', 1719707661000, 1719707661000, 1727796413552);
