INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (312, 15, NULL, NULL, 41, 'A Última Peça | Cinema', 'a-ultima-peca-cinema-pt-br', NULL, 'Longa-metragem de comédia infanto-juvenil estrelado pela youtuber Paula Stephânia, em exibição no Amazon Prime Video. A Farra é produtora associada e o roteiro é assinado por André Brandt e Gui Cintra.', 'published', '{"order":36,"image":"https://bucket.farra.media/a-ultima-peca.png","language":"ptbr","slug":"a-ultima-peca-cinema","videos":"https://vimeo.com/606874046","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Dire\u00e7\u00e3o","content":"Andr\u00e9 Moraes"},{"title":"Roteiro","content":"Andr\u00e9 Brandt e Gui Cintra"},{"title":"Distribui\u00e7\u00e3o","content":"Europa Filmes"},{"title":"Produ\u00e7\u00e3o","content":"Farra e Aquarela Filmes"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"17b254b8-488d-48b4-aa71-4314f0a7130e","legacy_posttype":"jobs","post_thumbnail_id":"311"}', 1716421964000, 1716421964000, 1727210117650);
