INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (314, 15, NULL, NULL, 41, 'ABERTO AO PÚBLICO | GLOBO', 'aberto-ao-publico-globo-pt-br', NULL, 'A plateia de pessoas anônimas como grande protagonista de um programa de TV com comediantes e celebridades. Foi com esse propósito que a Farra, em coprodução com a Dromedário, desenvolveu, produziu e pós-produziu duas temporadas de “Aberto ao Público”, humorístico da Globo que mistura comédia com uma dose generosa de despretensão, irreverência e uma constrangedora sinceridade, em um programa completamente imprevisível. Além dos episódios deste formato original, também produzimos peças extras de divulgação e microconteúdos verticais que invadiram as redes sociais da Globo, dos comediantes e convidados globais, mostrando os bastidores, erros de gravação e pérolas que só rolam quando se junta palco, plateia e humoristas soltos com um microfone.', 'published', '{"order":113,"image":"https://bucket.farra.media/Featured_Image_Site Farra.png","language":"ptbr","slug":"aberto-ao-publico-globo","videos":["https://vimeo.com/1162256512","https://vimeo.com/1162268067?fl=tl&fe=ec"],"videosHome":null,"videosHomeOrder":null,"fichaTecnica":[],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"da252e22-8a04-4eae-853a-35b416bbb7d7","legacy_posttype":"jobs","post_thumbnail_id":"313"}', 1767706214000, 1767706214000, 1770319540776);
