INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (316, 15, NULL, NULL, 41, 'Abertura Convenção | Nestlé', 'abertura-convencao-nestle-pt-br', NULL, 'Criação e produção de uma série de formatos para atender a necessidades internas de comunicação em tempos de pandemia. Como impactar de maneira virtual e audiovisual com a mesma eficiência dos tradicionais e grandiosos eventos físicos? A resposta foi uma série de programas de gêneros diferentes com muito entretenimento, informação e humor, que contaram com a participação de nomes importantes da comédia nacional, como Maurício Meirelles, Miá Mello e Daniel Zukerman.', 'published', '{"order":29,"image":"https://bucket.farra.media/Featured_Image_Site Farra-Recuperado.png","language":"ptbr","slug":"abertura-convencao-nestle","videos":"https://vimeo.com/587843046","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Produ\u00e7\u00e3o:","content":"Awake Film"},{"title":"Produ\u00e7\u00e3o Executiva:","content":"Gui Vieira "},{"title":"Dire\u00e7\u00e3o de Produ\u00e7\u00e3o:","content":"Tarcila Villa"},{"title":"Roteiro:","content":"Andr\u00e9 Brandt, Gui Cintra e Rodrigo Moura"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"383029f9-7f6f-4621-907f-aaba74fb18ae","legacy_posttype":"jobs","post_thumbnail_id":"315"}', 1727309792000, 1727309792000, 1727310894551);
