INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (322, 15, NULL, NULL, 39, 'Art Attack – Modo Desafio | Disney', 'art-attack-modo-desafio-disney-en-us', NULL, 'In an era where no one really watches anything "by themselves," Disney+ offered Art Attack fans the chance to enjoy the return of the iconic show alongside their idols—all from the comfort of home. To make this come true, Farra produced a live event on Disney+''s TikTok profile, featuring the original cast reacting to the first episode of the series while interacting with the live audience in real time.', 'published', '{"order":62,"image":"https://bucket.farra.media/disney-1.png","language":"enUS","slug":"art-attack-modo-desafio-disney","videos":"https://vimeo.com/863259550","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Cast:","content":"Tom, Caue, Carol, Paty e Maju"},{"title":"Direction:","content":"Leo Parron"},{"title":"Executive Production:","content":"Gui Vieira e Tayna Adam"},{"title":"Production Direction:","content":"Juliana Hodas"},{"title":"Coordination Casting:","content":"Tati Soares"},{"title":"Assistance Casting:","content":"Larissa Salles"},{"title":"Post-prodoction Coordination:","content":"Fred Kesselring"},{"title":"Production Assistance:","content":"Francielly Vidal"},{"title":"Financer:","content":"Andressa Souza"},{"title":"Social Media:","content":"Bruna Garcia"},{"title":"Production:","content":"Farra"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"0185068c-310a-4530-89f2-505ef0d6e2e7","legacy_posttype":"jobs","post_thumbnail_id":"321"}', 1727793901000, 1727793901000, 1727794175592);
