INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (324, 15, NULL, NULL, 41, 'Art Attack – Modo Desafio | Disney', 'art-attack-modo-desafio-disney-pt-br', NULL, 'Numa era em que ninguém assiste a nada realmente “sozinho”, a Disney+ trouxe ao público de Art Attack a possibilidade de acompanhar o retorno do icônico programa juntinho de seus ídolos. Tudo isso sem precisar sair de casa.Pra transformar isso em realidade, a Farra produziu uma live no perfil de Disney+, no TikTok, com direito ao elenco original reagindo ao primeiro episódio da série enquanto conversavam com o público da live em tempo real.', 'published', '{"order":63,"image":"https://bucket.farra.media/disney-1.png","language":"ptbr","slug":"art-attack-modo-desafio-disney","videos":"https://vimeo.com/863259550","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Apresenta\u00e7\u00e3o","content":"Tom, Caue, Carol, Paty e Maju"},{"title":"Dire\u00e7\u00e3o","content":"Leo Parron"},{"title":"Produ\u00e7\u00e3o Executiva","content":"Gui Vieira e Tayna Adam"},{"title":"Dire\u00e7\u00e3o de Produ\u00e7\u00e3o","content":"Juliana Hodas"},{"title":"Coordenadora de Casting","content":"Tati Soares"},{"title":"Assistente de Casting","content":"Larissa Salles"},{"title":"Coordenador de p\u00f3s","content":"Fred Kesselring"},{"title":"Assistente de Produ\u00e7\u00e3o","content":"Francielly Vidal"},{"title":"Financeiro","content":"Andressa Souza"},{"title":"Midias Sociais","content":"Bruna Garcia"},{"title":"Produ\u00e7\u00e3o","content":"Farra"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"7073bf8c-ed29-45ff-82c2-58b36ed72b3d","legacy_posttype":"jobs","post_thumbnail_id":"323"}', 1716477069000, 1716477069000, 1727185850635);
