INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (330, 15, NULL, NULL, 39, 'Batalha dos Eliminados | Splash UOL', 'batalha-dos-eliminados-splash-uol-en-us', NULL, 'To celebrate the 23 year history of Big Brother Brazil, we reunited 6 ex-participants from different editions of the reality show in order to discuss the show, reminisce about their craziest experiences and play elimination games based around the BBB universe.', 'published', '{"order":40,"image":"https://bucket.farra.media/bata.png","language":"enUS","slug":"batalha-dos-eliminados-splash-uol","videos":"https://vimeo.com/797370285","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Writing","content":"L\u00e9o Parron, S\u00e9rgio Barbosa e Ste Marques"},{"title":"Producer","content":"Farra"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"0ddc8793-4a32-4109-9d96-32c4a1b471e9","legacy_posttype":"jobs","post_thumbnail_id":"329"}', 1719707671000, 1719707671000, 1727796365439);
