INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (332, 15, NULL, NULL, 41, 'Batalha dos Eliminados | Splash UOL', 'batalha-dos-eliminados-splash-uol-pt-br', NULL, 'Para celebrar a história dos 23 anos de reality, além da edição atual, juntamos 6 ex-participantes do Big Brother Brasil em estúdio para discutirem sobre o reality, lembrarem fatos marcantes e disputarem games eliminatórios baseados no universo do BBB.', 'published', '{"order":41,"image":"https://bucket.farra.media/bata.png","language":"ptbr","slug":"batalha-dos-eliminados-splash-uol","videos":"https://vimeo.com/797370285","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Roteiro","content":"L\u00e9o Parron, S\u00e9rgio Barbosa e Ste Marques"},{"title":"Produ\u00e7\u00e3o e Cria\u00e7\u00e3o","content":"Farra"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"9879cf28-f8b8-4288-b009-5b6d8b8e4d8b","legacy_posttype":"jobs","post_thumbnail_id":"331"}', 1716423301000, 1716423301000, 1727209601967);
