INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (334, 15, NULL, NULL, 39, 'Boca a Boca | Live', 'boca-a-boca-live-en-us', NULL, 'Bianca Andrade (Boca Rosa) starred in the three seasons of this weekly show that, in addition to being a hit on Youtube, won the MTV MIAW 2020 Award. The 1-hour show featured artists such as: Pabllo Vittar, Alok, Luisa Sonza, Dulce Maria, Gloria Groove, Pocah, Less is More, Dilsinho, Diva Depression, Fábio Porchat, Sabrina Sato, Giulia Be, Pedro Sampaio, among others.', 'published', '{"order":79,"image":"https://bucket.farra.media/boca-1.png","language":"enUS","slug":"boca-a-boca-live","videos":"https://vimeo.com/557695860","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Executive Production","content":"Gui Vieira"},{"title":"Writing","content":"Andr\u00e9 Brandt"},{"title":"Direction","content":"Gui Cintra"},{"title":"Production","content":"Farra"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"472ee483-d526-48de-9898-478a60311879","legacy_posttype":"jobs","post_thumbnail_id":"333"}', 1719707501000, 1719707501000, 1727792449144);
