INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (336, 15, NULL, NULL, 41, 'Boca a Boca | Live', 'boca-a-boca-live-pt-br', NULL, 'Bianca Andrade (Boca Rosa) estrelou as três temporadas desse programa semanal que, além de bombar no Youtube, venceu o Prêmio MTV MIAW 2020. O programa, de 1 hora de duração, contou com participações de artistas como: Pabllo Vittar, Alok, Luisa Sonza, Dulce Maria, Gloria Groove, Pocah, Menos é Mais, Dilsinho, Diva Depressão, Fábio Porchat, Sabrina Sato, Giulia Be, Pedro Sampaio, dentre outros.', 'published', '{"order":80,"image":"https://bucket.farra.media/boca-1.png","language":"ptbr","slug":"boca-a-boca-live","videos":"https://vimeo.com/557695860","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Produ\u00e7\u00e3o Executiva","content":"Gui Vieira"},{"title":"Roteiro","content":"Andr\u00e9 Brandt"},{"title":"Dire\u00e7\u00e3o","content":"Gui Cintra"},{"title":"Produ\u00e7\u00e3o","content":"Farra"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"d04b5343-461f-4745-b0dc-c5babcde307e","legacy_posttype":"jobs","post_thumbnail_id":"335"}', 1716422725000, 1716422725000, 1726846336163);
