INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (338, 15, NULL, NULL, 39, 'Brasil Sabores Mil | Receitas Nestlé', 'brasil-sabores-mil-receitas-nestle-en-us', NULL, 'Development, creation, and production of shows for the "Receitas Nestlé" Channel and Portal, from Nestlé Brazil. In 2019 and 2020, with over 50 episodes of various shows  delivered for the brand''s channel in different formats: reality, talk-show, documentary, culinary, etc. Among the formats, standout titles include: Chocolateria, Põe Cremosidade Nisso, Deu Ruim, Nutri Ajuda, Brasil Sabores Mil, Receitas de Final de Semana, Mais Vividas, and Escolhas Certas. Under the "Receitas Nestlé" umbrella, the brands Molico, Maggi, Garoto, Nutren, Nestlé Cream, Nestlé Oats, Leite Moça, Nescafé, and Nestlé Health Science were represented.', 'published', '{"order":44,"image":"https://bucket.farra.media/8.png","language":"enUS","slug":"brasil-sabores-mil-receitas-nestle","videos":["https://vimeo.com/547714191","https://vimeo.com/547718487"],"videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Production:","content":"Awake Film"},{"title":"Executive Production:","content":"Gui Vieira "}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"2505f298-e6b8-4464-af6c-7ddae2eb1af9","legacy_posttype":"jobs","post_thumbnail_id":"337"}', 1727795609000, 1727795609000, 1727795645211);
