INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (340, 15, NULL, NULL, 41, 'Brasil Sabores Mil | Receitas Nestlé', 'brasil-sabores-mil-receitas-nestle-pt-br', NULL, 'Desenvolvimento, criação e produção de programas para o Canal e Portal “Receitas Nestlé”, da Nestlé Brasil. Em 2019 e 2020, foram entregues mais de 50 episódios de diferentes programas para o canal da marca, em diferentes formatos: reality, talk-show, documental, culinário, etc. Dentre os formatos, se destacam títulos como: Chocolateria, Põe Cremosidade Nisso, Deu Ruim, Nutri Ajuda, Brasil Sabores Mil, Receitas de Final de Semana, Mais Vividas e Escolhas Certas. No guarda chuva de Receitas Nestlé, foram atendidas as marcas Molico, Maggi, Garoto, Nutren, Creme de Leite Nestlé, Aveias Nestlé, Leite Moça, Nescafé, Nestlé Health Science.', 'published', '{"order":44,"image":"https://bucket.farra.media/8.png","language":"ptbr","slug":"brasil-sabores-mil-receitas-nestle","videos":["https://vimeo.com/547714191","https://vimeo.com/547718487"],"videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Produ\u00e7\u00e3o:","content":"Awake Film"},{"title":"Produ\u00e7\u00e3o Executiva:","content":"Gui Vieira "}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"93a8c5e7-1bda-4317-b24c-1a86eb0cd050","legacy_posttype":"jobs","post_thumbnail_id":"339"}', 1727209333000, 1727209333000, 1727358078106);
