INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (342, 15, NULL, NULL, 39, 'Café com Late Show | Nescafé', 'cafe-com-late-show-nescafe-en-us', NULL, 'Creation and production of a series of formats to meet internal communication needs during the pandemic. How to make a virtual and audiovisual impact with the same effectiveness as traditional large physical events? The answer was a series of  different genres shows, filled with entertainment, information, and humor, featuring prominent names from the national comedy scene, such as Maurício Meirelles, Miá Mello, and Daniel Zukerman.', 'published', '{"order":33,"image":"https://bucket.farra.media/9.png","language":"enUS","slug":"cafe-com-late-show-nescafe","videos":"https://vimeo.com/585908075","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"27e6049e-1ba7-425b-9eea-1250405f84bd","legacy_posttype":"jobs","post_thumbnail_id":"341"}', 1727796766000, 1727796766000, 1727796801108);
