INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (344, 15, NULL, NULL, 41, 'Café com Late Show | Nescafé', 'cafe-com-late-show-nescafe-pt-br', NULL, 'Desenvolvimento, criação e produção de programas para o Canal e Portal “Receitas Nestlé”, da Nestlé Brasil. Em 2019 e 2020, foram entregues mais de 50 episódios de diferentes programas para o canal da marca, em diferentes formatos: reality, talk-show, documental, culinário, etc. Dentre os formatos, se destacam títulos como: Chocolateria, Põe Cremosidade Nisso, Deu Ruim, Nutri Ajuda, Brasil Sabores Mil, Receitas de Final de Semana, Mais Vividas e Escolhas Certas. No guarda chuva de Receitas Nestlé, foram atendidas as marcas Molico, Maggi, Garoto, Nutren, Creme de Leite Nestlé, Aveias Nestlé, Leite Moça, Nescafé, Nestlé Health Science.', 'published', '{"order":34,"image":"https://bucket.farra.media/9.png","language":"ptbr","slug":"cafe-com-late-show-nescafe","videos":"https://vimeo.com/585908075","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"b443770d-9b8c-4d31-81db-7519bd162eea","legacy_posttype":"jobs","post_thumbnail_id":"343"}', 1727210643000, 1727210643000, 1727309872404);
