INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (346, 15, NULL, NULL, 39, 'CCXP Worlds 2020 | Omelete', 'ccxp-worlds-2020-omelete-en-us', NULL, 'Amid the social isolation of 2020, the largest in-person geek culture event in the world needed to reinvent itself in the virtual world.
CCXP Worlds was an ambitious project by the Omelete Company in which all the face-to-face panels of the event were transformed into a virtual experience. In all, 150 hours of content were broadcast, on 5 simultaneous stages over 3 days of event, which reached the public through an interactive gamified map. Numerous national and international panels reflected the major releases of cinema and television in 2020 and from major studios such as Paramount, Warner Media, Amazon Studios, Disney, etc. A great creation and production challenge developed in 2 months.', 'published', '{"order":65,"image":"https://bucket.farra.media/ccxp.png","language":"enUS","slug":"ccxp-worlds-2020-omelete","videos":["https://vimeo.com/557809467","https://vimeo.com/611903976"],"videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Executive Production","content":"Gui Vieira"},{"title":"Creation and writing","content":"Gui Cintra, Andr\u00e9 Brandt, Rodrigo Moura, Leo Parron e Maria Clara"},{"title":"Production Director","content":"Tarcila Villa"},{"title":"Production","content":"Omelete Company"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"b8d3bbd6-8594-47b0-a345-96f35a7004b6","legacy_posttype":"jobs","post_thumbnail_id":"345"}', 1719707450000, 1719707450000, 1727793510581);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (347, 6, NULL, NULL, NULL, 'ccxp.png', 'attachment-jobs-ccxp-worlds-2020-omelete-pt-br', NULL, NULL, 'published', '{"show_in_menu":false,"menu_options":[],"icon":"line-md:file","mime_type":"image/png","attachment_file":"ccxp.png","attachment_path":"https://bucket.farra.media/ccxp.png","attachment_alt":"CCXP Worlds 2020 | Omelete"}', NULL, 1716422609000, 1727185636338);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (348, 15, NULL, NULL, 41, 'CCXP Worlds 2020 | Omelete', 'ccxp-worlds-2020-omelete-pt-br', NULL, 'Em meio ao isolamento social de 2020, o maior evento presencial de cultura geek do mundo precisou se reinventar no mundo virtual. A CCXP WORLDS foi um projeto ambicioso da Omelete Company no qual todos os painéis presenciais do evento foram transformados em uma experiência virtual. Ao todo, foram 150 horas de conteúdo transmitidas, em 5 palcos simultâneos ao longo de 3 dias de evento, que chegava ao público através de um mapa interativo gamificado. Inúmeros painéis nacionais e internacionais repercutiram os grandes lançamentos do cinema e televisão de 2020 e dos grandes estúdios como Paramount, Warner Media, Amazon Studios, Disney, etc. Um grande desafio de criação e produção desenvolvido em 2 meses.', 'published', '{"order":66,"image":"https://bucket.farra.media/ccxp.png","language":"ptbr","slug":"ccxp-worlds-2020-omelete","videos":["https://vimeo.com/557809467","https://vimeo.com/611903976"],"videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Produ\u00e7\u00e3o Executiva","content":"Gui Vieira"},{"title":"Roteiro e Cria\u00e7\u00e3o","content":"Gui Cintra, Andr\u00e9 Brandt, Rodrigo Moura, Leo Parron e Maria Clara"},{"title":"Dire\u00e7\u00e3o de Produ\u00e7\u00e3o","content":"Tarcila Villa"},{"title":"Produ\u00e7\u00e3o","content":"Omelete Company"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"8b243bdd-ead1-4607-bee5-1f29ecbc53d4","legacy_posttype":"jobs","images":"[\"https://bucket.farra.media/8C1A8266-1024x683-1.jpg\",\"https://bucket.farra.media/8-c-1-a-9460.png\",\"https://bucket.farra.media/ccxp.png\"]","post_thumbnail_id":"347"}', 1716422609000, 1716422609000, 1727185636338);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (349, 6, NULL, NULL, NULL, 'camada-38-1.png', 'attachment-jobs-ccxp-worlds-2021-road-to-artists-valley-santander-en-us', NULL, NULL, 'published', '{"show_in_menu":false,"menu_options":[],"icon":"line-md:file","mime_type":"image/png","attachment_file":"camada-38-1.png","attachment_path":"https://bucket.farra.media/camada-38-1.png","attachment_alt":"CCXP Worlds 2021 \u2013 Road to Artists\u2019 Valley | Santander"}', NULL, 1719708368000, 1727792948112);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (350, 15, NULL, NULL, 39, 'CCXP Worlds 2021 – Road to Artists’ Valley | Santander', 'ccxp-worlds-2021-road-to-artists-valley-santander-en-us', NULL, 'Documentary series for CCXP 2021 about the heart of the event, Artists Valley. Divided into four episodes, the series tells about the history of comics until the arrival at the great CCXP event and the creation of Artists Valley, the sector destined for comic artists in the event that became the biggest event and the biggest reference in the world of comics in the world. Creation, Screenplay and Complete Production Farra for Omelete / CCXP partners.', 'published', '{"order":73,"image":"https://bucket.farra.media/camada-38-1.png","language":"enUS","slug":"ccxp-worlds-2021-road-to-artists-valley-santander","videos":["https://vimeo.com/667404932","https://vimeo.com/667413095","https://vimeo.com/667418524","https://vimeo.com/667428093"],"videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Executive Production","content":"Gui Vieira"},{"title":"Direction","content":"Leo Parron"},{"title":"Project Management","content":"Yasmin Persi"},{"title":"Writing","content":"Andr\u00e9 Brandt e Leo Parron"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"b330bc79-d4ca-4208-ad8b-79238c1c5a00","legacy_posttype":"jobs","post_thumbnail_id":"349"}', 1719708368000, 1719708368000, 1727792948112);
