INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (352, 15, NULL, NULL, 41, 'CCXP Worlds 2021 – Road to Artists’ Valley | Santander', 'ccxp-worlds-2021-road-to-artists-valley-santander-pt-br', NULL, 'Série documental para CCXP 2021 sobre o coração do evento, o Artists Valley. Dividido em quatro episódios a série conta sobre a história das comicons até a chegada no grande evento da CCXP e a criação do Artists Valley o setor destinado aos quadrinistas no evento que virou a maior evento e a maior referência no universo dos quadrinhos no mundo. Criação, Roteiro e Produção Completa Farra para os parceiros do Omelete / CCXP.', 'published', '{"order":74,"image":"https://bucket.farra.media/camada-38-1.png","language":"ptbr","slug":"ccxp-worlds-2021-road-to-artists-valley-santander","videos":["https://vimeo.com/667404932","https://vimeo.com/667413095","https://vimeo.com/667418524","https://vimeo.com/667428093"],"videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Produ\u00e7\u00e3o Executiva","content":"Gui Vieira"},{"title":"Dire\u00e7\u00e3o","content":"Leo Parron"},{"title":"Gest\u00e3o de Projetos","content":"Yasmin Persi"},{"title":"Roteiro","content":"Andr\u00e9 Brandt e Leo Parron"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"1a3831d7-5cac-4a28-a1e9-ef9ac3f1ddee","legacy_posttype":"jobs","post_thumbnail_id":"351"}', 1716424269000, 1716424269000, 1726846791483);
