INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (354, 15, NULL, NULL, 39, 'Chocolateria | Garoto', 'chocolateria-garoto-en-us', NULL, 'Development, creation, and production of shows for the "Receitas Nestlé" Channel and Portal, from Nestlé Brazil. In 2019 and 2020, with over 50 episodes of various shows  delivered for the brand''s channel in different formats: reality, talk-show, documentary, culinary, etc. Among the formats, standout titles include: Chocolateria, Põe Cremosidade Nisso, Deu Ruim, Nutri Ajuda, Brasil Sabores Mil, Receitas de Final de Semana, Mais Vividas, and Escolhas Certas. Under the "Receitas Nestlé" umbrella, the brands Molico, Maggi, Garoto, Nutren, Nestlé Cream, Nestlé Oats, Leite Moça, Nescafé, and Nestlé Health Science were represented.', 'published', '{"order":45,"image":"https://bucket.farra.media/5.png","language":"enUS","slug":"chocolateria-garoto","videos":["https://vimeo.com/547609502","https://vimeo.com/582597160","https://vimeo.com/558283365"],"videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Production:","content":"Awake Film"},{"title":"Executive Production:","content":"Gui Vieira "}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"39a783f2-5d8f-4cd3-b6f7-2c7d0c93594d","legacy_posttype":"jobs","post_thumbnail_id":"353"}', 1727795473000, 1727795473000, 1727796013152);
