INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (356, 15, NULL, NULL, 41, 'Chocolateria | Garoto', 'chocolateria-garoto-pt-br', NULL, 'Desenvolvimento, criação e produção de programas para o Canal e Portal “Receitas Nestlé”, da Nestlé Brasil. Em 2019 e 2020, foram entregues mais de 50 episódios de diferentes programas para o canal da marca, em diferentes formatos: reality, talk-show, documental, culinário, etc. Dentre os formatos, se destacam títulos como: Chocolateria, Põe Cremosidade Nisso, Deu Ruim, Nutri Ajuda, Brasil Sabores Mil, Receitas de Final de Semana, Mais Vividas e Escolhas Certas. No guarda chuva de Receitas Nestlé, foram atendidas as marcas Molico, Maggi, Garoto, Nutren, Creme de Leite Nestlé, Aveias Nestlé, Leite Moça, Nescafé, Nestlé Health Science.', 'published', '{"order":46,"image":"https://bucket.farra.media/5.png","language":"ptbr","slug":"chocolateria-garoto","videos":["https://vimeo.com/547609502","https://vimeo.com/582597160","https://vimeo.com/558283365"],"videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Produ\u00e7\u00e3o:","content":"Awake Film"},{"title":"Produ\u00e7\u00e3o Executiva:","content":"Gui Vieira "}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"8aaa0fa8-c18f-4601-ab35-5c79ab0b7511","legacy_posttype":"jobs","post_thumbnail_id":"355"}', 1727208329000, 1727208329000, 1727209966732);
