INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (358, 15, NULL, NULL, 39, 'Coach Nada | Laddy Nada', 'coach-nada-laddy-nada-en-us', NULL, 'Comedian Gabriel Rocha (@laddynada) starred in his first webseries for the Instagram platform, produced and created by Farra. The proposal was to create a comedy drama series for the 9:16 format. The series has in the cast with the participation of Cleo, Vitor DiCastro, Lucas Guedez and Dani Calabresa. Project nominated for Best Vertical Series at Rio Web Fest 2020.', 'published', '{"order":20,"image":"https://bucket.farra.media/coach-1.png","language":"enUS","slug":"coach-nada-laddy-nada","videos":"https://vimeo.com/557300363","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Direction","content":"Gui Cintra"},{"title":"Writing","content":"Gui Cintra e Andr\u00e9 Brandt"},{"title":"Production and creation","content":"Farra"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"f691c8e0-873a-492b-a132-d32e0ac5430c","legacy_posttype":"jobs","post_thumbnail_id":"357"}', 1719706445000, 1719706445000, 1727798008116);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (359, 6, NULL, NULL, NULL, 'coach-1.png', 'attachment-jobs-coach-nada-laddy-nada-pt-br', NULL, NULL, 'published', '{"show_in_menu":false,"menu_options":[],"icon":"line-md:file","mime_type":"image/png","attachment_file":"coach-1.png","attachment_path":"https://bucket.farra.media/coach-1.png","attachment_alt":"Coach Nada | Laddy Nada"}', NULL, 1716420851000, 1727310553866);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (360, 15, NULL, NULL, 41, 'Coach Nada | Laddy Nada', 'coach-nada-laddy-nada-pt-br', NULL, 'O humorista Gabriel Rocha (@laddynada) estrelou sua primeira websérie para a plataforma Instagram com produção e criação da Farra. A proposta era criar uma série de dramaturgia de comédia para o formato 9:16. A série conta no elenco com as participações de Cleo, Vitor DiCastro, Lucas Guedez e Dani Calabresa. Projeto indicado a Melhor Série Vertical no Rio Web Fest 2020.', 'published', '{"order":21,"image":"https://bucket.farra.media/coach-1.png","language":"ptbr","slug":"coach-nada-laddy-nada","videos":"https://vimeo.com/557300363","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Dire\u00e7\u00e3o","content":"Gui Cintra"},{"title":"Roteiro","content":"Gui Cintra e Andr\u00e9 Brandt"},{"title":"Produ\u00e7\u00e3o e Cria\u00e7\u00e3o","content":"Farra"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"00a8df26-484e-4278-930b-d4734bec87ac","legacy_posttype":"jobs","images":"[\"https://bucket.farra.media/944928372_1280x720.jpg\",\"https://bucket.farra.media/laddy-nada-gabriel-rocha.jpg\",\"https://bucket.farra.media/gabriel-rocha-e-dani-calabresa.jpg\"]","post_thumbnail_id":"359"}', 1716420851000, 1716420851000, 1727310553866);
