INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (362, 15, NULL, NULL, 39, 'commercial convention | Nestlé', 'commercial-convention-nestle-en-us', NULL, 'Creation and production of a series of formats to meet internal communication needs during the pandemic. How to make a virtual and audiovisual impact with the same effectiveness as traditional large physical events? The answer was a series of  different genres shows, filled with entertainment, information, and humor, featuring prominent names from the national comedy scene, such as Maurício Meirelles, Miá Mello, and Daniel Zukerman.', 'published', '{"order":30,"image":"https://bucket.farra.media/a.png","language":"enUS","slug":"commercial-convention-nestle","videos":"https://vimeo.com/585561977","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Executive Producer:","content":"Gui Vieira "},{"title":"Production:","content":"Awake Film"},{"title":"Direction Production:","content":"Tarcila Villa"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"d21f757e-f03b-4490-9c27-aa13e46e6168","legacy_posttype":"jobs","post_thumbnail_id":"361"}', 1727796982000, 1727796982000, 1727797218783);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (363, 6, NULL, NULL, NULL, 'compro-likes.png', 'attachment-jobs-compro-likes-star-en-us', NULL, NULL, 'published', '{"show_in_menu":false,"menu_options":[],"icon":"line-md:file","mime_type":"image/png","attachment_file":"compro-likes.png","attachment_path":"https://bucket.farra.media/compro-likes.png","attachment_alt":"Compro Likes | Star+"}', NULL, 1727796438000, 1727796515435);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (364, 15, NULL, NULL, 39, 'Compro Likes | Star+', 'compro-likes-star-en-us', NULL, 'Wagner is a struggling actor who wants to achieve stardom but pays the bills by entertaining at nursing homes and children''s parties. He can no longer stand being turned down at every audition he attends. After many frustrating attempts, he comes up with a plan alongside his friend Sarah and turns to the eccentric guru Johnny Silva to learn how to become famous at any cost. Following the guru''s advice, he creates a life based on lies on social media. The plan works like a charm: he gets millions of followers and becomes a celebrity! Things change when he is approached by an American director for his first real movie role. However, not everything is as easy as it seems.', 'published', '{"order":38,"image":"https://bucket.farra.media/compro-likes.png","language":"enUS","slug":"compro-likes-star","videos":"https://vimeo.com/870268328","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Casting:","content":"F\u00e1bio Lago e Ana Carol Machado"},{"title":"Creation:","content":"Andr\u00e9 Brandt e Andr\u00e9 Moraes"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"2573b7ef-7863-4fa1-8ba3-de558bcdb2c6","legacy_posttype":"jobs","post_thumbnail_id":"363"}', 1727796438000, 1727796438000, 1727796515435);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (365, 6, NULL, NULL, NULL, 'compro-likes.png', 'attachment-jobs-compro-likes-star-pt-br', NULL, NULL, 'published', '{"show_in_menu":false,"menu_options":[],"icon":"line-md:file","mime_type":"image/png","attachment_file":"compro-likes.png","attachment_path":"https://bucket.farra.media/compro-likes.png","attachment_alt":"Compro Likes | Star+"}', NULL, 1716423110000, 1727209827240);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (366, 15, NULL, NULL, 41, 'Compro Likes | Star+', 'compro-likes-star-pt-br', NULL, 'Wagner é um ator fracassado que deseja alcançar o estrelato, mas paga as contas animando asilos e festinhas infantis. Ele não suporta mais ser rejeitado em todos os testes de elenco dos quais participa. Depois de muitas tentativas frustradas, ele bola um plano com a amiga Sarah e recorre ao excêntrico guru Johnny Silva para aprender como ficar famoso a qualquer custo. A partir do conselho do professor, cria uma vida baseada em mentiras nas redes sociais. O plano funciona maravilhosamente bem: ele ganha milhões de seguidores e se torna uma celebridade! As coisas mudam quando ele é chamado por um diretor americano para seu primeiro papel no cinema, desta vez, de verdade. Porém, nem tudo são flores e glamour.', 'published', '{"order":39,"image":"https://bucket.farra.media/compro-likes.png","language":"ptbr","slug":"compro-likes-star","videos":"https://vimeo.com/870268328","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Estrelando","content":"F\u00e1bio Lago e Ana Carol Machado"},{"title":"Cria\u00e7\u00e3o","content":"Andr\u00e9 Brandt e Andr\u00e9 Moraes"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"4c30d855-a05e-4826-9476-93c05f26c4a5","legacy_posttype":"jobs","post_thumbnail_id":"365"}', 1716423110000, 1716423110000, 1727209827240);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (367, 6, NULL, NULL, NULL, 'ste.png', 'attachment-jobs-conselho-fora-de-classe-videocast-en-us', NULL, NULL, 'published', '{"show_in_menu":false,"menu_options":[],"icon":"line-md:file","mime_type":"image/png","attachment_file":"ste.png","attachment_path":"https://bucket.farra.media/ste.png","attachment_alt":"Conselho Fora de Classe | Videocast"}', NULL, 1727798795000, 1727798855232);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (368, 15, NULL, NULL, 39, 'Conselho Fora de Classe | Videocast', 'conselho-fora-de-classe-videocast-en-us', NULL, 'Created and produced in-house, the videocast "Conselho Fora de Classe" is hosted by Ste Marques, known among her followers as the ex-teacher who speaks her mind! Ste and her guests dive headfirst into this videocast, ready to unearth the funniest, most embarrassing, and humiliating stories from their school days', 'published', '{"order":13,"image":"https://bucket.farra.media/ste.png","language":"enUS","slug":"conselho-fora-de-classe-videocast","videos":"https://vimeo.com/870269610","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Starring:","content":"Ste Marques"},{"title":"Coordination Production:","content":"Ju Hodas"},{"title":"Project Manager: ","content":"Rosa Taques"},{"title":"Art:","content":"Beatriz Vidal"},{"title":"Production and creation:","content":"Farra"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"fb05fd21-e6db-44a3-960a-e68f95a1c3ed","legacy_posttype":"jobs","post_thumbnail_id":"367"}', 1727798795000, 1727798795000, 1727798855232);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (369, 6, NULL, NULL, NULL, 'ste.png', 'attachment-jobs-conselho-fora-de-classe-videocast-pt-br', NULL, NULL, 'published', '{"show_in_menu":false,"menu_options":[],"icon":"line-md:file","mime_type":"image/png","attachment_file":"ste.png","attachment_path":"https://bucket.farra.media/ste.png","attachment_alt":"Conselho Fora de Classe | Videocast"}', NULL, 1716479452000, 1727310747870);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (370, 15, NULL, NULL, 41, 'Conselho Fora de Classe | Videocast', 'conselho-fora-de-classe-videocast-pt-br', NULL, 'Criado e produzido na casa, o videocast Conselho Fora de Classe é apresentado por Ste Marques, famosa entre seus seguidores como a ex-professora que não tem papas na língua! Ste e seus convidados mergulham de cabeça nesse videocast, prontos pra desenterrar as histórias mais engraçadas, constrangedoras e humilhantes da época da escola.', 'published', '{"order":15,"image":"https://bucket.farra.media/ste.png","language":"ptbr","slug":"conselho-fora-de-classe-videocast","videos":"https://vimeo.com/870269610","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Estrelando","content":"Ste Marques"},{"title":"Coordena\u00e7\u00e3o de Produ\u00e7\u00e3o","content":"Ju Hodas"},{"title":"Gest\u00e3o de Projeto","content":"Rosa Taques"},{"title":"Arte","content":"Beatriz Vidal"},{"title":"Produ\u00e7\u00e3o e Cria\u00e7\u00e3o","content":"Farra"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"d081d323-ee73-4341-a77e-ef0854d775d2","legacy_posttype":"jobs","post_thumbnail_id":"369"}', 1716479452000, 1716479452000, 1727310747870);
