INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (372, 15, NULL, NULL, 41, 'CONTROLE DE QUALIDADE com REGINA VOLPATO | PARAMOUNT +', 'controle-de-qualidade-com-regina-volpato-paramount-pt-br', NULL, 'A Farra criou e produziu uma nova campanha para o Paramount+, estrelada por Regina Volpato, com o intuito de promover as séries dramáticas do streaming – sem deixar de lado o bom humor, que é uma característica do povo brasileiro. Sob a direção de Gui Cintra e seguindo o conceito “Viciados em um bom drama”, a proposta é evidenciar que a plataforma tem se tornado uma referência quando o assunto é oferecer um forte catálogo do gênero para o público brasileiro, que, assim como o Paramount+, é apaixonado em um bom drama.', 'published', '{"order":104,"image":"https://bucket.farra.media/REGUN.png","language":"ptbr","slug":"controle-de-qualidade-com-regina-volpato-paramount","videos":"https://vimeo.com/1068297412","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Produ\u00e7\u00e3o:","content":"Farra"},{"title":"Dire\u00e7\u00e3o: ","content":"Gui Cintra"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"277c4ea1-b389-445d-bda1-4e861a8cbb33","legacy_posttype":"jobs","post_thumbnail_id":"371"}', 1751023761000, 1751023761000, 1767788657409);
