INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (374, 15, NULL, NULL, 39, 'Convention Opening | Nestlé', 'convention-opening-nestle-en-us', NULL, 'Creation and production of a series of formats to meet internal communication needs during the pandemic. How to make a virtual and audiovisual impact with the same effectiveness as traditional large physical events? The answer was a series of  different genres shows, filled with entertainment, information, and humor, featuring prominent names from the national comedy scene, such as Maurício Meirelles, Miá Mello, and Daniel Zukerman.', 'published', '{"order":28,"image":"https://bucket.farra.media/Featured_Image_Site Farra-Recuperado.png","language":"enUS","slug":"convention-opening-nestle","videos":"https://vimeo.com/587843046","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Production:","content":"Awake Film"},{"title":"Executive Production:","content":"Gui Vieira "},{"title":"Direction Production:","content":"Tarcila Villa"},{"title":"Writing:","content":"Andr\u00e9 Brandt, Gui Cintra e Rodrigo Moura"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"41a44572-dab3-4bfd-aa53-f4e26db5560f","legacy_posttype":"jobs","post_thumbnail_id":"373"}', 1727797245000, 1727797245000, 1727797313652);
