INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (380, 15, NULL, NULL, 41, 'Convenção Comercial | Nestlé', 'convencao-comercial-nestle-pt-br', NULL, 'Criação e produção de uma série de formatos para atender a necessidades internas de comunicação em tempos de pandemia. Como impactar de maneira virtual e audiovisual com a mesma eficiência dos tradicionais e grandiosos eventos físicos? A resposta foi uma série de programas de gêneros diferentes com muito entretenimento, informação e humor, que contaram com a participação de nomes importantes da comédia nacional, como Maurício Meirelles, Miá Mello e Daniel Zukerman.', 'published', '{"order":30,"image":"https://bucket.farra.media/a.png","language":"ptbr","slug":"convencao-comercial-nestle","videos":"https://vimeo.com/585561977","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Produ\u00e7\u00e3o Executiva:","content":"Gui Vieira "},{"title":"Produ\u00e7\u00e3o:","content":"Awake Film"},{"title":"Dire\u00e7\u00e3o de Produ\u00e7\u00e3o:","content":"Tarcila Villa"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"f33f1d64-8c8e-42fe-b31f-369b18324dd2","legacy_posttype":"jobs","post_thumbnail_id":"379"}', 1727269498000, 1727269498000, 1727310882700);
