INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (382, 15, NULL, NULL, 41, 'Convenção | Nestlé', 'convencao-nestle-pt-br', NULL, 'Criação e produção de uma série de formatos para atender a necessidades internas de comunicação em tempos de pandemia. Como impactar de maneira virtual e audiovisual com a mesma eficiência dos tradicionais e grandiosos eventos físicos? A resposta foi uma série de programas de gêneros diferentes com muito entretenimento, informação e humor, que contaram com a participação de nomes importantes da comédia nacional, como Maurício Meirelles, Miá Mello e Daniel Zukerman.', 'published', '{"order":2,"image":"https://bucket.farra.media/convencao-nestle-2.png","language":"ptbr","slug":"convencao-nestle","videos":["https://vimeo.com/585908075","https://vimeo.com/585911802","https://vimeo.com/585908075","https://vimeo.com/586460367","https://vimeo.com/585906391","https://vimeo.com/583955226"],"videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Produ\u00e7\u00e3o Executiva","content":"Guilherme Vieira"},{"title":"Dire\u00e7\u00e3o de Produ\u00e7\u00e3o","content":"Tarcila Villa"},{"title":"Roteiro e Cria\u00e7\u00e3o","content":"Gui Cintra, Dani Garuti e Andr\u00e9 Brandt"},{"title":"Dire\u00e7\u00e3o","content":"Gui Cintra"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"7d36d993-d21a-44a3-bf5d-4984494e7da0","legacy_posttype":"jobs","post_thumbnail_id":"381"}', 1716421602000, 1716421602000, 1727470346217);
