INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (384, 15, NULL, NULL, 41, 'Convenção | Starbucks', 'convencao-starbucks-pt-br', NULL, 'Desenvolvimento, criação e produção de programas para o Canal e Portal “Receitas Nestlé”, da Nestlé Brasil. Em 2019 e 2020, foram entregues mais de 50 episódios de diferentes programas para o canal da marca, em diferentes formatos: reality, talk-show, documental, culinário, etc. Dentre os formatos, se destacam títulos como: Chocolateria, Põe Cremosidade Nisso, Deu Ruim, Nutri Ajuda, Brasil Sabores Mil, Receitas de Final de Semana, Mais Vividas e Escolhas Certas. No guarda chuva de Receitas Nestlé, foram atendidas as marcas Molico, Maggi, Garoto, Nutren, Creme de Leite Nestlé, Aveias Nestlé, Leite Moça, Nescafé, Nestlé Health Science.', 'published', '{"order":28,"image":"https://bucket.farra.media/c.png","language":"ptbr","slug":"convencao-starbucks","videos":"https://vimeo.com/585561071","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Dire\u00e7\u00e3o:","content":"Gui Cintra"},{"title":"Produ\u00e7\u00e3o Executiva:","content":"Gui Vieira "},{"title":"Roteiro: ","content":"Andr\u00e9 Brandt"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"e1da0aee-c515-4833-af9d-bc061b218900","legacy_posttype":"jobs","post_thumbnail_id":"383"}', 1727310101443, 1727310101443, 1728385196617);
