INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (386, 15, NULL, NULL, 39, 'Corrida de São Sylvester | Paramount+', 'corrida-de-sao-sylvester-paramount-en-us', NULL, 'Paramount+ approached the entertainment agency Farra to create promotional material for the new series "Tulsa King". We created the São Sylvester Race, an official street race in honor of the great star Sylvester Stallone, the star of the series. The intention was to unite all the fame of Sylvester Stallone''s iconic characters and introduce his new character in Tulsa King, "Dwight Manfredi". The race was free and took place at the São Paulo Botanical Garden. Fans were encouraged to dress up as their favorite Stallone characters. At the event, many activations connected with the Tulsa King series, and all the set design, country band and stages of the event referred to the universe of the series. We created a registration website, produced more than 10 advertising films, including announcements, stories, pre-, during and post-event promos and hero film, in addition to the entire production of the race.', 'published', '{"order":95,"image":"https://bucket.farra.media/corrida.png","language":"enUS","slug":"corrida-de-sao-sylvester-paramount","videos":["https://vimeo.com/1010371240","https://vimeo.com/1010371031","https://vimeo.com/1010370651"],"videosHome":["https://vimeo.com/1010371240"],"videosHomeOrder":null,"fichaTecnica":[{"title":"Agency and Production:","content":"Farra"},{"title":"Creation and Writing:","content":"Gui Cintra, Andr\u00e9 Brandt, Maria Clara Lucci, Sergio Barbosa, Rodrigo Moura"},{"title":"Direction:","content":"Gui Cintra"},{"title":"Executive Production:","content":"Gui Vieira e Tayna Adam"},{"title":"Production Direction:","content":"Juliana Hodas"},{"title":"Steering Assistance:","content":"Sophia Cordazzo"},{"title":"Production:","content":"Jo\u00e3o Pedro Mello"},{"title":"Executive Production Assistance:","content":"Beatriz Fontana"},{"title":"Art Production:","content":"Jenny Shauff"},{"title":"Costume:","content":"Fabiana Souza"},{"title":"Make: ","content":"Dani Gonc"},{"title":"Cinematography:","content":"Heitor Cavalheiro"},{"title":"Post-production Coordination:","content":"Fred Kesselring"},{"title":"Edition:","content":"Mike Prado"},{"title":"Color Correction:","content":"Hugo Moura"},{"title":"Art Direction:","content":"Gustavo Moura"},{"title":"Motion Design:","content":"Alex Kundera "},{"title":"Design:","content":"Bia Vidal"},{"title":"Audio:","content":"Gui Picolo - Dream Box"},{"title":"Financial Coordination:","content":"Andressa Carrijo"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"150f88d8-0aab-4c39-a3c8-f0f21bdb5103","legacy_posttype":"jobs","post_thumbnail_id":"385"}', 1726763360000, 1726763360000, 1767787931732);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (387, 6, NULL, NULL, NULL, 'corrida.png', 'attachment-jobs-corrida-de-sao-sylvester-paramount-pt-br', NULL, NULL, 'published', '{"show_in_menu":false,"menu_options":[],"icon":"line-md:file","mime_type":"image/png","attachment_file":"corrida.png","attachment_path":"https://bucket.farra.media/corrida.png","attachment_alt":"Corrida de S\u00e3o Sylvester | Paramount+"}', NULL, 1726762026000, 1767788371649);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (388, 15, NULL, NULL, 41, 'Corrida de São Sylvester | Paramount+', 'corrida-de-sao-sylvester-paramount-pt-br', NULL, 'A Paramount+ buscou a agência de entretenimento Farra para criar peças para divulgação da nova série "Tulsa King", criamos assim a: Corrida de São Sylvester, uma corrida de rua oficial em homenagem ao grande astro Sylvester Stallone protagonista da série. A intenção foi unir toda fama dos personagens icônicos do Sylvester Stallone e apresentar seu novo personagem em Tulsa King "Dwight Manfredi". A corrida foi gratuita e aconteceu no Jardim Botânico de São Paulo, os fãs foram estimulados a irem fantasiados dos seus personagens favoritos do Stallone, no evento, muitas ativações conectavam com os núcleos da série Tulsa King, e todo cenografia, banda country e palcos do evento remetiam ao universo da série. Criamos site de inscrições, produção de mais de 10 filmes publicitários, entre chamadas, stories, promo pré, durante e pós evento e filme hero, além claro de toda a produção da corrida.', 'published', '{"order":100,"image":"https://bucket.farra.media/corrida.png","language":"ptbr","slug":"corrida-de-sao-sylvester-paramount","videos":["https://vimeo.com/1010371240","https://vimeo.com/1010371031","https://vimeo.com/1010370651"],"videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Ag\u00eancia e Produ\u00e7\u00e3o","content":"Farra"},{"title":"Cria\u00e7\u00e3o e Reda\u00e7\u00e3o:","content":"Gui Cintra, Andr\u00e9 Brandt, Maria Clara Lucci, Sergio Barbosa, Rodrigo Moura"},{"title":"Dire\u00e7\u00e3o","content":"Gui Cintra"},{"title":"Produ\u00e7\u00e3o Executiva:","content":"Gui Vieira e Tayna Adam"},{"title":"Dire\u00e7\u00e3o de Produ\u00e7\u00e3o:","content":"Juliana Hodas"},{"title":"Assist\u00eancia de Dire\u00e7\u00e3o:","content":"Sophia Cordazzo"},{"title":"Produ\u00e7\u00e3o:","content":"Jo\u00e3o Pedro Mello"},{"title":"Assist\u00eancia de Produ\u00e7\u00e3o Executiva:","content":"Beatriz Fontana"},{"title":"Produ\u00e7\u00e3o de Arte:","content":"Jenny Shauff"},{"title":"Figurino:","content":"Fabiana Souza"},{"title":"Make: ","content":"Dani Gonc"},{"title":"Dire\u00e7\u00e3o de Fotografia:","content":"Heitor Cavalheiro"},{"title":"Coordena\u00e7\u00e3o de P\u00f3s-produ\u00e7\u00e3o:","content":"Fred Kesselring"},{"title":"Edi\u00e7\u00e3o:","content":"Mike Prado"},{"title":"Corre\u00e7\u00e3o de Cor:","content":"Hugo Moura"},{"title":"Dire\u00e7\u00e3o de Arte:","content":"Gustavo Moura"},{"title":"Motion Design:","content":"Alex Kundera "},{"title":"Design:","content":"Bia Vidal"},{"title":"\u00c1udio:","content":"Gui Picolo - Dream Box"},{"title":"Coordena\u00e7\u00e3o Financeira:","content":"Andressa Carrijo"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"f476b2d2-7936-45a7-a1ff-1591f015619e","legacy_posttype":"jobs","post_thumbnail_id":"387"}', 1726762026000, 1726762026000, 1767788371649);
