INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (390, 15, NULL, NULL, 39, 'Creators | Kwai', 'creators-kwai-en-us', NULL, 'With the arrival of Kwai in Brazil in 2021, Farra closed a partnership to create original comedy content for some creators of the platform. We offer: curatorship, creation, script, direction and post-production. The project had 100 videos delivered in 30 days: 20 videos a week, to 5 different creators. One-minute humor sketches. A true content production line.', 'published', '{"order":34,"image":"https://bucket.farra.media/kwai.png","language":"enUS","slug":"creators-kwai","videos":"https://vimeo.com/602092851","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Executive Production","content":"Guilherme Vieira"},{"title":"Writing","content":"Maria Clara, Victor Ahmar, Gui Cintra e Andr\u00e9 Brandt"},{"title":"Production","content":"Farra"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"ba4aa3fa-4b53-4a0d-9d8c-559e3b0c4cd8","legacy_posttype":"jobs","post_thumbnail_id":"389"}', 1719707214000, 1719707214000, 1727796740115);
