INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (392, 15, NULL, NULL, 41, 'Creators | Kwai', 'creators-kwai-pt-br', NULL, 'Com a chegada da Kwai no Brasil em 2021, a Farra fechou uma parceria para criar conteúdos de comédia originais para alguns creators da plataforma. Oferecemos: curadoria, criação, roteiro, direção e pós-produção. O projeto teve 100 vídeos entregues em 30 dias: 20 vídeos por semana, para 5 creators diferentes. Esquetes de humor com duração de um minuto. Uma verdadeira linha de produção de conteúdo', 'published', '{"order":35,"image":"https://bucket.farra.media/kwai.png","language":"ptbr","slug":"creators-kwai","videos":"https://vimeo.com/602092851","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Produ\u00e7\u00e3o Executiva","content":"Guilherme Vieira"},{"title":"Roteiro","content":"Maria Clara, Victor Ahmar, Gui Cintra e Andr\u00e9 Brandt"},{"title":"Produ\u00e7\u00e3o","content":"Farra"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"9ee014c3-ab81-4ca0-aecb-f2dd3564b945","legacy_posttype":"jobs","post_thumbnail_id":"391"}', 1716421886000, 1716421886000, 1727210147576);
