INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (394, 15, NULL, NULL, 39, 'CTRL SER + CTRL VER | UNIVERSA UOL', 'ctrl-ser-ctrl-ver-universa-uol-en-us', NULL, 'Farra was invited by UOL – Universo Online to develop a project for Universa that mixed the fashion scene, influencers, beauty and the internet’s modernity. Then “Ctrl-ser + Ctrl-ver” was born. The show is hosted by Laura Vicente, who receives a famous guest each episode to discuss their fashion world refs.', 'published', '{"order":61,"image":"https://bucket.farra.media/ctrl.png","language":"enUS","slug":"ctrl-ser-ctrl-ver-universa-uol","videos":"https://vimeo.com/797398819","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Executive Production","content":"Gui Vieira"},{"title":"Direction","content":"Leo Parron"},{"title":"Writing","content":"Macla Lucci e Leo Parron"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"d45cc6e8-ad10-415d-bac7-c4c3fb4b4783","legacy_posttype":"jobs","post_thumbnail_id":"393"}', 1719708667000, 1719708667000, 1727311143089);
