INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (396, 15, NULL, NULL, 41, 'CTRL SER + CTRL VER | UNIVERSA UOL', 'ctrl-ser-ctrl-ver-universa-uol-pt-br', NULL, 'A Farra foi convidada pelo UOL – Universo Online para formatar um projeto para o Universa que envolvesse o mundo da Moda, influencers, beauty e a modernindade da internet.Assim nasceu o “Crtl Ser + Crtl Ver” é um programa apresentado pela Laura Vicente em que, a cada episódio, recebe uma convidada famosa para contar sobre suas referências do mundo da moda.', 'published', '{"order":61,"image":"https://bucket.farra.media/ctrl.png","language":"ptbr","slug":"ctrl-ser-ctrl-ver-universa-uol","videos":"https://vimeo.com/797398819","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Produ\u00e7\u00e3o Executiva","content":"Gui Vieira"},{"title":"Dire\u00e7\u00e3o","content":"Leo Parron"},{"title":"Roteiro","content":"Macla Lucci e Leo Parron"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"b7d63740-a369-4f2e-b6fd-b8d1069e5a64","legacy_posttype":"jobs","post_thumbnail_id":"395"}', 1716465399000, 1716465399000, 1727311166139);
