INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (400, 15, NULL, NULL, 41, 'Curso Livelo | Livelo', 'curso-livelo-livelo-pt-br', NULL, 'A Farra desenvolveu e produziu um curso de 7 episódios para a Livelo, apresentando de forma divertida para a audiência todas as funcionalidades do mundo dos pontos. Os vídeos dessa série foram apresentados pelo fenômeno Thati Lopes e dirigidos pelo nosso sócio e diretor Gui Cintra. Para quem tiver interesse, o curso completo está postado nas redes da Livelo!', 'published', '{"order":95,"image":"https://bucket.farra.media/livelo.png","language":"ptbr","slug":"curso-livelo-livelo","videos":"https://vimeo.com/1010376650","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Ag\u00eancias:","content":"Almap BBDO e Voz"},{"title":"Produtora: ","content":"Farra"},{"title":"Dire\u00e7\u00e3o:","content":"Gui Cintra"},{"title":"Produ\u00e7\u00e3o Executiva:","content":"Gui Vieira e Tayna Adam"},{"title":"Cria\u00e7\u00e3o e Reda\u00e7\u00e3o:","content":"Rodrigo Moura, Maria Clara Lucci, Gui Cintra e Sergio"},{"title":"Motion Design","content":"Serginho Dimi"},{"title":"Dire\u00e7\u00e3o de Arte:","content":"Beatriz Vidal"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"abcf4fb6-b566-480e-9047-51cfd25f8017","legacy_posttype":"jobs","post_thumbnail_id":"399"}', 1727791328848, 1727791328848, 1727791328848);
