INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (402, 15, NULL, NULL, 39, 'De Volta Para um Futuro Melhor | Nestlé', 'de-volta-para-um-futuro-melhor-nestle-en-us', NULL, 'Creation and production of a series of formats to meet internal communication needs during the pandemic. How to make a virtual and audiovisual impact with the same effectiveness as traditional large physical events? The answer was a series of  different genres shows, filled with entertainment, information, and humor, featuring prominent names from the national comedy scene, such as Maurício Meirelles, Miá Mello, and Daniel Zukerman.', 'published', '{"order":31,"image":"https://bucket.farra.media/10.png","language":"enUS","slug":"de-volta-para-um-futuro-melhor-nestle","videos":["https://vimeo.com/586003554","https://vimeo.com/586460367"],"videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Production:","content":"Awake Film"},{"title":"Executive Production:","content":"Gui Vieira "}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"c2f56d58-b4a8-4e22-b1e7-1a9a05820b0f","legacy_posttype":"jobs","post_thumbnail_id":"401"}', 1727796931000, 1727796931000, 1727796959241);
