INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (404, 15, NULL, NULL, 41, 'De Volta Para um Futuro Melhor | Nestlé', 'de-volta-para-um-futuro-melhor-nestle-pt-br', NULL, 'Criação e produção de uma série de formatos para atender a necessidades internas de comunicação em tempos de pandemia. Como impactar de maneira virtual e audiovisual com a mesma eficiência dos tradicionais e grandiosos eventos físicos? A resposta foi uma série de programas de gêneros diferentes com muito entretenimento, informação e humor, que contaram com a participação de nomes importantes da comédia nacional, como Maurício Meirelles, Miá Mello e Daniel Zukerman.', 'published', '{"order":33,"image":"https://bucket.farra.media/10.png","language":"ptbr","slug":"de-volta-para-um-futuro-melhor-nestle","videos":["https://vimeo.com/586003554","https://vimeo.com/586460367"],"videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Produ\u00e7\u00e3o:","content":"Awake Film"},{"title":"Produ\u00e7\u00e3o Executiva:","content":"Gui Vieira "}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"8ee7c930-ad8e-4e85-9242-243249b5e6f4","legacy_posttype":"jobs","post_thumbnail_id":"403"}', 1727211188000, 1727211188000, 1727310824336);
