INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (406, 15, NULL, NULL, 39, 'Desejos S.A. | STAR+', 'desejos-sa-star-en-us', NULL, 'André Brandt and Gui Cintra collaborated on the script for this series by award-winning Argentine filmmakers Mariano Cohn and Gastón Duprat. The project is produced by Moovie and aired on Star+.', 'published', '{"order":64,"image":"https://bucket.farra.media/desejos.png","language":"enUS","slug":"desejos-sa-star","videos":"https://vimeo.com/922015100","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"COLABORA\u00c7\u00c3O DE ROTEIRO","content":"Gui Cintra e Andr\u00e9 Brandt"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"424d6724-3f06-485d-b88a-9582f9834ad0","legacy_posttype":"jobs","post_thumbnail_id":"405"}', 1716477957000, 1716477957000, 1727793573493);
