INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (409, 6, NULL, NULL, NULL, 'n.png', 'attachment-jobs-deu-ruim-receitas-nestle-en-us', NULL, NULL, 'published', '{"show_in_menu":false,"menu_options":[],"icon":"line-md:file","mime_type":"image/png","attachment_file":"n.png","attachment_path":"https://bucket.farra.media/n.png","attachment_alt":"Deu Ruim | Receitas Nestl\u00e9"}', NULL, 1727795392000, 1728932034397);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (410, 15, NULL, NULL, 39, 'Deu Ruim | Receitas Nestlé', 'deu-ruim-receitas-nestle-en-us', NULL, 'Development, creation, and production of shows for the "Receitas Nestlé" Channel and Portal, from Nestlé Brazil. In 2019 and 2020, with over 50 episodes of various shows  delivered for the brand''s channel in different formats: reality, talk-show, documentary, culinary, etc. Among the formats, standout titles include: Chocolateria, Põe Cremosidade Nisso, Deu Ruim, Nutri Ajuda, Brasil Sabores Mil, Receitas de Final de Semana, Mais Vividas, and Escolhas Certas. Under the "Receitas Nestlé" umbrella, the brands Molico, Maggi, Garoto, Nutren, Nestlé Cream, Nestlé Oats, Leite Moça, Nescafé, and Nestlé Health Science were represented.', 'published', '{"order":47,"image":"https://bucket.farra.media/n.png","language":"enUS","slug":"deu-ruim-receitas-nestle","videos":["https://vimeo.com/582209977","https://vimeo.com/586467179","https://vimeo.com/557771327"],"videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Production:","content":"Awake Film"},{"title":"Executive Production:","content":"Gui Vieira"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"9f1b39f9-8ac1-44fb-b71c-51622fa97052","legacy_posttype":"jobs","post_thumbnail_id":"409"}', 1727795392000, 1727795392000, 1728932034397);
