INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (414, 15, NULL, NULL, 41, 'DEVS DE IMPACTO | OPEN AI', 'devs-de-impacto-open-ai-pt-br', NULL, 'Com produção da Farra, o encontro internacional reuniu desenvolvedores, líderes de tecnologia e criadores em um dia dedicado à inovação e às possibilidades da inteligência artificial. Da ambientação à experiência dos convidados, a Farra assinou toda a produção, criando um espaço de troca, aprendizado e conexão entre as comunidades de tecnologia.', 'draft', '{"order":0,"image":"https://bucket.farra.media/SITE.png","language":"ptbr","slug":"devs-de-impacto-open-ai","videos":"https://vimeo.com/1148055555","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"8642631f-3aa6-4dc1-a3c3-1807902bf57f","legacy_posttype":"jobs","post_thumbnail_id":"413"}', 1767706545000, 1767706545000, 1769537572994);
