INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (424, 15, NULL, NULL, 39, 'Diário do Olivier | GNT', 'diario-do-olivier-gnt-en-us', NULL, 'Chef Olivier Anquier’s program for the GNT channel. It was on the air for 20 years, ending its last season in 2017. Gui Vieira produced and directed, in 2016 and 2017, the seasons: France, Australia, Thailand and India. In 2013 and 2014, he produced the seasons: China, Turkey, South Africa and Mozambique.', 'published', '{"order":12,"image":"https://bucket.farra.media/diario.png","language":"enUS","slug":"diario-do-olivier-gnt","videos":["https://vimeo.com/223556677","https://vimeo.com/216625129","https://vimeo.com/216611693","https://vimeo.com/216608050","https://vimeo.com/216604939","https://vimeo.com/216621780","https://vimeo.com/216618531","https://vimeo.com/216596499","https://vimeo.com/216597629","https://vimeo.com/228102874","https://vimeo.com/228105737","https://vimeo.com/228100098","https://vimeo.com/228111975","https://vimeo.com/228121022","https://vimeo.com/228118105","https://vimeo.com/228115088","https://vimeo.com/228108820","https://vimeo.com/223563101","https://vimeo.com/228124743","https://vimeo.com/216615273","https://vimeo.com/228097134","","","","","","",""],"videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Direction and Production","content":"Guilherme Vieira"},{"title":"Producer","content":"Bossa Nova Films"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"d4c7c585-2e6f-443f-abab-64bfcf56327b","legacy_posttype":"jobs","post_thumbnail_id":"423"}', 1719706290000, 1719706290000, 1727798267885);
