INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (426, 15, NULL, NULL, 41, 'Diário do Olivier | GNT', 'diario-do-olivier-gnt-pt-br', NULL, 'Programa do Chef Olivier Anquier para o canal GNT. Ficou 20 anos no ar, encerrando sua última temporada em 2017. Gui Vieira produziu e dirigiu, em 2016 e 2017, as temporadas: França, Austrália, Tailândia e Índia. Em 2013 e 2014, produziu as temporadas: China, Turquia, África do Sul e Moçambique.', 'published', '{"order":13,"image":"https://bucket.farra.media/diario.png","language":"ptbr","slug":"diario-do-olivier-gnt","videos":["https://vimeo.com/223563101","https://vimeo.com/228105737","https://vimeo.com/216621780","https://vimeo.com/228097134","https://vimeo.com/223556677","https://vimeo.com/216625129","https://vimeo.com/228115088","https://vimeo.com/216618531","https://vimeo.com/228100098","https://vimeo.com/216615273","https://vimeo.com/216595784","https://vimeo.com/216608050","https://vimeo.com/228111975","https://vimeo.com/228121022","https://vimeo.com/228118105","https://vimeo.com/228115088","https://vimeo.com/228108820","https://vimeo.com/223563101","https://vimeo.com/228124743","https://vimeo.com/216615273","https://vimeo.com/228097134"],"videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Dire\u00e7\u00e3o e Produ\u00e7\u00e3o","content":"Guilherme Vieira"},{"title":"Produ\u00e7\u00e3o","content":"Bossa Nova Films"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"8c33e6cf-c459-45e6-9bf2-1151439eada2","legacy_posttype":"jobs","post_thumbnail_id":"425"}', 1716420217000, 1716420217000, 1738791146474);
