INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (428, 15, NULL, NULL, 39, 'Do que Riem? | Paramount+', 'do-que-riem-paramount-en-us', NULL, 'Two comedians face off in a stand-up dispute. In each episode, they must prepare a different number, for a specific type of audience – such as doctors, hairdressers, bodybuilders, grannies, among others – and whoever does better, in the opinion of the audience, wins the battle. Broadcasted by Comedy Central and hosted by Maurício Meirelles, ‘Do Que Riem?’ is more than a comedy show, it is a social experiment and a tribute to comedy and its particularities.', 'published', '{"order":105,"image":"https://bucket.farra.media/dqr.png","language":"enUS","slug":"do-que-riem-paramount","videos":"https://vimeo.com/869578633","videosHome":["https://vimeo.com/869578633"],"videosHomeOrder":null,"fichaTecnica":[{"title":"Host","content":"Mauricio Meirelles"},{"title":"Comedians","content":"Babu Carreira e Jhordan Matheus"},{"title":"Executive Production","content":"Ju Hodas"},{"title":"Production Assistant","content":"Francielly Vidal"},{"title":"Casting","content":"Tati Soares e Larissa Salles"},{"title":"Post-production Coordinator","content":"Fred Kesselring"},{"title":"Finance Manager","content":"Andressa Souza"},{"title":"Main Director","content":"Gui Cintra"},{"title":"2nd Unit Director","content":"Leo Parron"},{"title":"Writing","content":"Leo Parron, S\u00e9rgio Barbosa, Ste Marques e Rodrigo Moura"},{"title":"Editing","content":"Lucas Nascimento"},{"title":"Design","content":"Beatriz Vidal"},{"title":"Production","content":"Farra"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"f05f3ff4-59b8-4134-a3ce-d15005b6c257","legacy_posttype":"jobs","post_thumbnail_id":"427"}', 1719709227000, 1719709227000, 1727799430697);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (429, 6, NULL, NULL, NULL, 'dqr.png', 'attachment-jobs-do-que-riem-paramount-pt-br', NULL, NULL, 'published', '{"show_in_menu":false,"menu_options":[],"icon":"line-md:file","mime_type":"image/png","attachment_file":"dqr.png","attachment_path":"https://bucket.farra.media/dqr.png","attachment_alt":"Do Que Riem? | Paramount+"}', NULL, 1716477547000, 1767703166494);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (430, 15, NULL, NULL, 41, 'Do Que Riem? | Paramount+', 'do-que-riem-paramount-pt-br', NULL, 'Dois comediantes se enfrentam numa disputa de stand-up. A cada episódio, eles devem preparar um texto diferente, para um tipo de público específico – como médicos, cabeleireiras, marombas, vovós, entre outros – e, quem se sair melhor, na opinião da plateia, vence a batalha.Transmitido pelo Comedy Central e apresentado por Maurício Meirelles, ‘Do Que Riem?’ é mais que um programa de humor, é um experimento social e uma homenagem à comédia e suas particularidades.', 'published', '{"order":111,"image":"https://bucket.farra.media/dqr.png","language":"ptbr","slug":"do-que-riem-paramount","videos":"https://vimeo.com/847396010","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Apresentador","content":"Mauricio Meirelles"},{"title":"Humoristas","content":"Babu Carreira e Jhordan Matheus"},{"title":"Produ\u00e7\u00e3o Executiva","content":"Ju Hodas"},{"title":"Assistente de Produ\u00e7\u00e3o","content":"Francielly Vidal"},{"title":"Casting","content":"Tati Soares e Larissa Salles"},{"title":"Coordena\u00e7\u00e3o de Produ\u00e7\u00e3o","content":"Fred Kesselring"},{"title":"Financeiro","content":"Andressa Souza"},{"title":"Dire\u00e7\u00e3o Geral","content":"Gui Cintra"},{"title":"Dire\u00e7\u00e3o de Externas","content":"Leo Parron"},{"title":"Roteiro","content":"Leo Parron, S\u00e9rgio Barbosa, Ste Marques e Rodrigo Moura"},{"title":"Edi\u00e7\u00e3o","content":"Lucas Nascimento"},{"title":"Arte","content":"Beatriz Vidal"},{"title":"Produ\u00e7\u00e3o","content":"Farra"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"e1b821b8-d78e-43b1-9f74-4264f5ad8947","legacy_posttype":"jobs","post_thumbnail_id":"429"}', 1716477547000, 1716477547000, 1767703166494);
