INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (432, 15, NULL, NULL, 39, 'Donos da Razão | Podcast', 'donos-da-razao-podcast-en-us', NULL, 'Escaping the stereotype of romantic love, Donos da Razão is the space where Foquinha and André Brandt, the rolezeiro couple, use the complicity of their relationship to discuss the relationship based on facts and events.', 'published', '{"order":42,"image":"https://bucket.farra.media/donos.png","language":"enUS","slug":"donos-da-razao-podcast","videos":"https://vimeo.com/798886289","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Starring","content":"Andr\u00e9 Brandt e Foquinha"},{"title":"Writing","content":"Maria Clara Lucci"},{"title":"Project Management","content":"Rosa Taques"},{"title":"Design","content":"Angelo Ramos"},{"title":"Production","content":"Farra"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"d7d1ac1a-1e1d-4d32-83b0-f2fa868e5bcb","legacy_posttype":"jobs","post_thumbnail_id":"431"}', 1719709245000, 1719709245000, 1727796141407);
