INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (434, 15, NULL, NULL, 41, 'Donos da Razão | Podcast', 'donos-da-razao-podcast-pt-br', NULL, 'Em 2023, com uma nova identidade visual desenvolvida pela Farra. Fugindo do estereótipo do amor romântico, Donos da Razão é o espaço onde Foquinha e André Brandt, o casal rolezeiro, usa da cumplicidade do relacionamento para discutir a relação em cima de fatos e acontecimentos.', 'published', '{"order":43,"image":"https://bucket.farra.media/donos.png","language":"ptbr","slug":"donos-da-razao-podcast","videos":"https://vimeo.com/798886289","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Estrelando","content":"Andr\u00e9 Brandt e Foquinha"},{"title":"Roteiro","content":"Maria Clara Lucci"},{"title":"Gest\u00e3o de Projeto","content":"Rosa Taques"},{"title":"Arte","content":"Angelo Ramos"},{"title":"Produ\u00e7\u00e3o","content":"Farra"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"a483fb50-4d74-4f33-abca-e386f129e3fe","legacy_posttype":"jobs","post_thumbnail_id":"433"}', 1716478551000, 1716478551000, 1727209395659);
