INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (436, 15, NULL, NULL, 39, 'El Camino com Mauricio Meirelles | Netflix', 'el-camino-com-mauricio-meirelles-netflix-en-us', NULL, 'Film and series releases for Netflix with completely different plots and proposals: “El Camino”, a Breaking Bad film with Maurício Meirelles included in the self-help group; “Elite”, with MC Kevinho, where we recreated the murdered man’s party and included Kevinho in the deposition room with the series’ police chief; “Eu Resolvi Esperar”, a campaign with Sandy for the launch of the second season of La Casa de Papel; “The Crown”, with the participation of Queen Elza Soares; and “Roma”, to promote Alfonso Cuarón’s Oscar-winning film.', 'published', '{"order":8,"image":"https://bucket.farra.media/h.png","language":"enUS","slug":"el-camino-com-mauricio-meirelles-netflix","videos":"https://vimeo.com/545673202","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Executive Producer:","content":"Gui Vieira "}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"eddeb559-6ffd-47bd-a9ed-8f07f59b5be2","legacy_posttype":"jobs","post_thumbnail_id":"435"}', 1727798977000, 1727798977000, 1727799005834);
