INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (438, 15, NULL, NULL, 41, 'El Camino com Mauricio Meirelles | Netflix', 'el-camino-com-mauricio-meirelles-netflix-pt-br', NULL, 'Lançamentos de filmes e séries para Netflix com enredos e propostas totalmente distintas: “El Camino”, um filme de Breaking Bad com Maurício Meirelles inserido no grupo de autoajuda; “Elite”, com MC Kevinho, onde refizemos a festa do assassinado e incluímos Kevinho na sala de depoimento com a delegada da série; “Eu Resolvi Esperar”, campanha com Sandy para lançamento da segunda temporada de La Casa de Papel; “The Crown”, com participação da rainha Elza Soares; e “Roma”, para promoção do filme de Alfonso Cuarón, vencedor do Oscar.', 'published', '{"order":9,"image":"https://bucket.farra.media/h.png","language":"ptbr","slug":"el-camino-com-mauricio-meirelles-netflix","videos":"https://vimeo.com/545673202","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Produ\u00e7\u00e3o Executiva:","content":"Gui Vieira "}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"5566a7a5-381d-4553-ac63-2e505235664e","legacy_posttype":"jobs","post_thumbnail_id":"437"}', 1727312438314, 1727312438314, 1728385329116);
