INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (440, 15, NULL, NULL, 41, 'Energia Verde | Heineken', 'energia-verde-heineken-pt-br', NULL, 'A grande marca cervejeira buscou a Farra para a produção dos materiais audiovisuais das novas campanhas voltadas ao uso de energia verde na produção e comercialização de uma das cervejas mais amadas do Brasil.', 'published', '{"order":75,"image":"https://bucket.farra.media/heine.png","language":"ptbr","slug":"energia-verde-heineken","videos":"https://vimeo.com/765732245","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Dire\u00e7\u00e3o","content":"Leo Parron"},{"title":"Produ\u00e7\u00e3o Executiva","content":"Gui Vieira e Tarcila Villa"},{"title":"Produ\u00e7\u00e3o","content":"Farra"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"57ac0f0c-30b0-4256-8282-e3afbf8da245","legacy_posttype":"jobs","post_thumbnail_id":"439"}', 1716465398000, 1716465398000, 1726846654162);
