INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (442, 15, NULL, NULL, 39, 'Escolhas Certas | Maggi', 'escolhas-certas-maggi-en-us', NULL, 'Development, creation, and production of shows for the "Receitas Nestlé" Channel and Portal, from Nestlé Brazil. In 2019 and 2020, with over 50 episodes of various shows  delivered for the brand''s channel in different formats: reality, talk-show, documentary, culinary, etc. Among the formats, standout titles include: Chocolateria, Põe Cremosidade Nisso, Deu Ruim, Nutri Ajuda, Brasil Sabores Mil, Receitas de Final de Semana, Mais Vividas, and Escolhas Certas. Under the "Receitas Nestlé" umbrella, the brands Molico, Maggi, Garoto, Nutren, Nestlé Cream, Nestlé Oats, Leite Moça, Nescafé, and Nestlé Health Science were represented.', 'published', '{"order":43,"image":"https://bucket.farra.media/7.png","language":"enUS","slug":"escolhas-certas-maggi","videos":"https://vimeo.com/547728947","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Direction:","content":"Awake Film"},{"title":"Executive Direction:","content":"Gui Vieira "},{"title":"Direction Production:","content":"Tarcila Villa"},{"title":"Creation and Writing:","content":"Gui Cintra e Andr\u00e9 Brandt e Dani Guti"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"d6e78f37-0fef-45ff-8776-de833534f0f3","legacy_posttype":"jobs","post_thumbnail_id":"441"}', 1727795668000, 1727795668000, 1727795761207);
