INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (444, 15, NULL, NULL, 41, 'Escolhas Certas | Maggi', 'escolhas-certas-maggi-pt-br', NULL, 'Desenvolvimento, criação e produção de programas para o Canal e Portal “Receitas Nestlé”, da Nestlé Brasil. Em 2019 e 2020, foram entregues mais de 50 episódios de diferentes programas para o canal da marca, em diferentes formatos: reality, talk-show, documental, culinário, etc. Dentre os formatos, se destacam títulos como: Chocolateria, Põe Cremosidade Nisso, Deu Ruim, Nutri Ajuda, Brasil Sabores Mil, Receitas de Final de Semana, Mais Vividas e Escolhas Certas. No guarda chuva de Receitas Nestlé, foram atendidas as marcas Molico, Maggi, Garoto, Nutren, Creme de Leite Nestlé, Aveias Nestlé, Leite Moça, Nescafé, Nestlé Health Science.', 'published', '{"order":45,"image":"https://bucket.farra.media/7.png","language":"ptbr","slug":"escolhas-certas-maggi","videos":"https://vimeo.com/547728947","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Dire\u00e7\u00e3o:","content":"Awake Film"},{"title":"Produ\u00e7\u00e3o Executiva:","content":"Gui Vieira "},{"title":"Dire\u00e7\u00e3o de Produ\u00e7\u00e3o:","content":"Tarcila Villa"},{"title":"Roteiro e Cria\u00e7\u00e3o:","content":"Gui Cintra e Andr\u00e9 Brandt e Dani Guti"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"188ef951-6153-4ccc-9bc5-9aa57bdd89b3","legacy_posttype":"jobs","post_thumbnail_id":"443"}', 1727209029000, 1727209029000, 1727358692180);
