INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (446, 15, NULL, NULL, 41, 'Especial Luca | Disney', 'especial-luca-disney-pt-br', NULL, 'A Farra criou, roteirizou e produziu as peças da campanha audiovisual do lançamento do filme Luca, da Disney/Pixar. Foram 4 ações distintas: uma série de peças e fotos para divulgação para imprensa com entrevistas e peças para o digital com os dubladores do filme Luís Miranda, Claudia Raia e Sophia Raia; uma esquete de comédia com Luís, Claudia e Sophia; uma live com Dani Calabresa para divulgação no dia do lançamento do filme; uma websérie com o lado italianissimo de Dani Calabresa para divulgação em suas redes.', 'published', '{"order":79,"image":"https://bucket.farra.media/K.png","language":"ptbr","slug":"especial-luca-disney","videos":"https://vimeo.com/569549244","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Produ\u00e7\u00e3o:","content":"Farra"},{"title":"Dire\u00e7\u00e3o:","content":"Gui Cintra"},{"title":"Roteiro:","content":"Andr\u00e9 Brandt"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"8f8a3b1c-eeb5-4410-9562-b90b86413538","legacy_posttype":"jobs","post_thumbnail_id":"445"}', 1727792462147, 1727792462147, 1727792462147);
