INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (456, 15, NULL, NULL, 39, 'Father''s Day | Farfetch', 'fathers-day-farfetch-en-us', NULL, 'Pedro Novaes stars in this beautiful Father''s Day campaign for the brand Farfetch. An audio message sent to his father, Marcelo Novaes, is illustrated with stunning images photographed and directed by Hugo Moura.', 'published', '{"order":87,"image":"https://bucket.farra.media/farf.png","language":"enUS","slug":"fathers-day-farfetch","videos":"https://vimeo.com/1010378685","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Direction:","content":"Hugo Moura"},{"title":"Cast:","content":"Marcello Novaes e Pedro Novaes"},{"title":"Cinematography:","content":"Jesus Mendes"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"a738a5a4-3a0d-4932-9eea-14d9a0779136","legacy_posttype":"jobs","post_thumbnail_id":"455"}', 1726764492000, 1726764492000, 1727792375461);
