INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (458, 15, NULL, NULL, 39, 'Foca em 2020 | Live', 'foca-em-2020-live-en-us', NULL, 'Even with many adversities, 2020 was a year of many events in the pop world. Infinite memes, unforgettable musical partnerships, series that made us happy during social isolation and no one better to remember that than Foquinha. Over more than 4 hours of live content, the live featured artists such as Pabllo Vittar, Emicida and Anitta.', 'published', '{"order":18,"image":"https://bucket.farra.media/focaaa.png","language":"enUS","slug":"foca-em-2020-live","videos":["https://vimeo.com/585646949","https://vimeo.com/625455102"],"videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Direction","content":"Gui Cintra"},{"title":"Writing","content":"Gui Cintra e Andr\u00e9 Brandt"},{"title":"Production and creation","content":"Farra"},{"title":"Producer","content":"Farra"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"4e382559-f374-4d00-86ea-3dfc9348316f","legacy_posttype":"jobs","post_thumbnail_id":"457"}', 1719706387000, 1719706387000, 1727798213563);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (459, 6, NULL, NULL, NULL, 'focaaa.png', 'attachment-jobs-foca-em-2020-live-pt-br', NULL, NULL, 'published', '{"show_in_menu":false,"menu_options":[],"icon":"line-md:file","mime_type":"image/png","attachment_file":"focaaa.png","attachment_path":"https://bucket.farra.media/focaaa.png","attachment_alt":"Foca em 2020 | Live"}', NULL, 1716420518000, 1727312731575);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (460, 15, NULL, NULL, 41, 'Foca em 2020 | Live', 'foca-em-2020-live-pt-br', NULL, 'Mesmo com muitas adversidades, 2020 foi um ano de muitos acontecimentos no mundo pop. Memes infinitos, parcerias musicais inesquecíveis, séries que fizeram a nossa alegria durante o isolamento social e ninguém melhor para relembrar isso do que a Foquinha. Ao longo de mais de 4 horas de conteúdo ao vivo, a live contou com a participação de artistas como Pabllo Vittar, Emicida e Anitta.', 'published', '{"order":19,"image":"https://bucket.farra.media/focaaa.png","language":"ptbr","slug":"foca-em-2020-live","videos":["https://vimeo.com/585646949","https://vimeo.com/625455102"],"videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Dire\u00e7\u00e3o","content":"Gui Cintra"},{"title":"Roteiro","content":"Gui Cintra e Andr\u00e9 Brandt"},{"title":"Produ\u00e7\u00e3o e Cria\u00e7\u00e3o","content":"Farra"},{"title":"Produ\u00e7\u00e3o","content":"Farra"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"d6dbca63-93cd-4fee-9b69-cb71c5c569a7","legacy_posttype":"jobs","images":"[\"https://bucket.farra.media/020202.png\",\"https://bucket.farra.media/foca.jpg\"]","post_thumbnail_id":"459"}', 1716420518000, 1716420518000, 1727312731575);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (461, 6, NULL, NULL, NULL, 'foquinha.png', 'attachment-jobs-foca-em-2021-tik-tok-en-us', NULL, NULL, 'published', '{"show_in_menu":false,"menu_options":[],"icon":"line-md:file","mime_type":"image/png","attachment_file":"foquinha.png","attachment_path":"https://bucket.farra.media/foquinha.png","attachment_alt":"Foca em 2021 | Tik Tok"}', NULL, 1719708334000, 1727795037891);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (462, 15, NULL, NULL, 39, 'Foca em 2021 | Tik Tok', 'foca-em-2021-tik-tok-en-us', NULL, 'Repeating the success of 2020, the Foquinha’s retrospective returned in the following year with “Foca in 2021”. In partnership with Tik Tok, the live program was shown exclusively on the platform, in 9:16 format, and featured guest appearances by Pequena Lô, Boca Rosa and Fred, Diva Depressão, Victor DiCastro, Vittor Fernando, Fefê, Esse Menino and Bela.', 'published', '{"order":53,"image":"https://bucket.farra.media/foquinha.png","language":"enUS","slug":"foca-em-2021-tik-tok","videos":"https://vimeo.com/674433361","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Direction","content":"Gui Cintra"},{"title":"Executive Production","content":"Guilherme Vieira"},{"title":"Production","content":"Farra"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"0790caac-9c2a-4e87-80e3-9d537c0e7b5e","legacy_posttype":"jobs","post_thumbnail_id":"461"}', 1719708334000, 1719708334000, 1727795037891);
