INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (464, 15, NULL, NULL, 41, 'Foca em 2021 | Tik Tok', 'foca-em-2021-tik-tok-pt-br', NULL, 'Repetindo o sucesso de 2020, a retrospectiva da Foquinha voltou no ano seguinte com o “Foca em 2021”. Em parceria com o Tik Tok, o programa ao vivo foi exibido com exclusividade na plataforma, no formato 9:16, e contou com as participações especiais de Pequena Lô, Boca Rosa e Fred, Diva Depressão, Victor DiCastro, Vittor Fernando, Fefê, Esse Menino e Bielo.', 'published', '{"order":54,"image":"https://bucket.farra.media/foquinha.png","language":"ptbr","slug":"foca-em-2021-tik-tok","videos":"https://vimeo.com/674433361","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Dire\u00e7\u00e3o","content":"Gui Cintra"},{"title":"Produ\u00e7\u00e3o Executiva","content":"Guilherme Vieira"},{"title":"Produ\u00e7\u00e3o","content":"Farra"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"a6137a12-d61f-413c-bc22-1b7a09bc7c48","legacy_posttype":"jobs","post_thumbnail_id":"463"}', 1716424145000, 1716424145000, 1727186378028);
