INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (470, 15, NULL, NULL, 39, 'Foi Mau | RedeTV!', 'foi-mau-redetv-en-us', NULL, 'Maurício Meirelles is a great friend of Farra. When the invitation to produce his show for open TV came up, we didn’t think twice about embarking on it with him. Weekly view, every Monday. It’s the craziest, most random talk show you’ve ever seen!', 'published', '{"order":72,"image":"https://bucket.farra.media/foi-mau.png","language":"enUS","slug":"foi-mau-redetv","videos":["https://vimeo.com/733662287","https://vimeo.com/798892768"],"videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Direction","content":"Gui Cintra"},{"title":"Writing","content":"Rodrigo Moura, Andr\u00e9 Brandt, Sergio Barbosa e Gui Cintra"},{"title":"Executive Production","content":"Guilherme Vieira"},{"title":"Co-Production","content":"Farra"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"aeea607b-5a18-4005-9744-336943aaec45","legacy_posttype":"jobs","post_thumbnail_id":"469"}', 1719708594000, 1719708594000, 1727793100645);
