INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (472, 15, NULL, NULL, 41, 'Foi Mau | RedeTV!', 'foi-mau-redetv-pt-br', NULL, 'Maurício Meirelles é um grande amigo da Farra. Quando surgiu o convite para produzirmos o seu programa para a TV aberta, não pensamos duas vezes em embarcar nessa com ele. Exibição semanal, toda segunda-feira. É o talk-show mais maluco e aleatório que você já viu!', 'published', '{"order":73,"image":"https://bucket.farra.media/foi-mau.png","language":"ptbr","slug":"foi-mau-redetv","videos":["https://vimeo.com/733662287","https://vimeo.com/798892768"],"videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Dire\u00e7\u00e3o","content":"Gui Cintra"},{"title":"Roteiro","content":"Rodrigo Moura, Andr\u00e9 Brandt, Sergio Barbosa e Gui Cintra"},{"title":"Produ\u00e7\u00e3o Executiva","content":"Guilherme Vieira"},{"title":"Co-Produ\u00e7\u00e3o","content":"Farra"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"265eca86-c62f-4069-aeb4-82b08281b1bd","legacy_posttype":"jobs","post_thumbnail_id":"471"}', 1716465397000, 1716465397000, 1726846906129);
