INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (474, 15, NULL, NULL, 39, 'Foquinha Entrevista | Videocast', 'foquinha-entrevista-videocast-en-us', NULL, 'The iconic interviews are back! Foquinha Entrevista is now a videocast! That sincere, intimate, and fun conversation, but in a new way!', 'published', '{"order":60,"image":"https://bucket.farra.media/Foquinha-entrevista.png","language":"enUS","slug":"foquinha-entrevista-videocast","videos":"https://vimeo.com/863259189","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Cast:","content":"Foquinha"},{"title":"Production:","content":"Farra"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"65246331-b6ed-44ee-bd2b-20e7d4f9d32a","legacy_posttype":"jobs","post_thumbnail_id":"473"}', 1727794522000, 1727794522000, 1727794586553);
