INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (476, 15, NULL, NULL, 41, 'Foquinha Entrevista | Videocast', 'foquinha-entrevista-videocast-pt-br', NULL, 'As entrevistas icônicas voltaram! Foquinha Entrevista agora é videocast! Aquele papo sincerão, íntimo e divertido, de um jeito novo!', 'published', '{"order":62,"image":"https://bucket.farra.media/Foquinha-entrevista.png","language":"ptbr","slug":"foquinha-entrevista-videocast","videos":"https://vimeo.com/863259189","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Estrelando","content":"Foquinha"},{"title":"Produ\u00e7\u00e3o","content":"Farra"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"f626f534-1f58-4925-8d66-b2b193f4b3f2","legacy_posttype":"jobs","post_thumbnail_id":"475"}', 1716477067000, 1716477067000, 1727185962110);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (477, 6, NULL, NULL, NULL, 'gp.png', 'attachment-jobs-gastronomia-periferica-continental-en-us', NULL, NULL, 'published', '{"show_in_menu":false,"menu_options":[],"icon":"line-md:file","mime_type":"image/png","attachment_file":"gp.png","attachment_path":"https://bucket.farra.media/gp.png","attachment_alt":"Gastronomia Perif\u00e9rica | Continental"}', NULL, 1719709013000, 1727792297896);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (478, 15, NULL, NULL, 39, 'Gastronomia Periférica | Continental', 'gastronomia-periferica-continental-en-us', NULL, 'The Peripheral Gastronomy project, created by Edson Leite and Adélia Rodrigues, has always enchanted Farra precisely because of its premise: talking and teaching about gastronomy to an audience that needs quality information and training.

Transforming the knowledge spread by the GP people into content for the internet (increasing the project’s reach even more) was necessary, and identifying the lack of this type of content on the internet was fundamental to start building the GP channel on YouTube, back in 2018 .

It took 2 years to present the project, knocking from door to door, looking for partners to get this idea off the ground. Until we found at Continental Eletrodomésticos and SOKO the perfect sponsors to make it happen.

A project made by the periphery and for the periphery, which puts Farra face to face with other players in the digital market, always with excellence in production and purpose!', 'published', '{"order":82,"image":"https://bucket.farra.media/gp.png","language":"enUS","slug":"gastronomia-periferica-continental","videos":["https://vimeo.com/720732573","https://vimeo.com/720738724","https://vimeo.com/720743549","https://vimeo.com/720746990","https://vimeo.com/720754306","https://vimeo.com/733744331\""],"videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Executive Production","content":"Gui Vieira"},{"title":"Project Management","content":"Yasmin Persi"},{"title":"Production Coordinator","content":"Tarcila Vila"},{"title":"Writing","content":"Sergio Barbosa e L\u00e9o Parron"},{"title":"Production and creation","content":"Farra"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"7fa3c1f4-15b3-4238-a7d7-62be004367cf","legacy_posttype":"jobs","post_thumbnail_id":"477"}', 1719709013000, 1719709013000, 1727792297896);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (479, 6, NULL, NULL, NULL, 'gp.png', 'attachment-jobs-gastronomia-periferica-continental-pt-br', NULL, NULL, 'published', '{"show_in_menu":false,"menu_options":[],"icon":"line-md:file","mime_type":"image/png","attachment_file":"gp.png","attachment_path":"https://bucket.farra.media/gp.png","attachment_alt":"Gastronomia Perif\u00e9rica | Continental"}', NULL, 1716476838000, 1726862744561);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (480, 15, NULL, NULL, 41, 'Gastronomia Periférica | Continental', 'gastronomia-periferica-continental-pt-br', NULL, 'O projeto Gastronomia Periférica, criado por Edson Leite e Adélia Rodrigues, sempre encantou a Farra justamente por sua premissa: falar e ensinar sobre gastronomia para um público que precisa de informação e formação de qualidade.Transformar o conhecimento espalhado pela galera da GP em conteúdo para internet (aumentando ainda mais o alcance do projeto) era algo necessário, e identificar a falta desse tipo de conteúdo na internet foi fundamental para começar a construção do canal GP no YouTube, lá em 2018.  Foram 2 anos apresentando o projeto, batendo de porta em porta, na busca de parceiros para tirar essa ideia do papel. Até que encontramos na Continental Eletrodomésticos e na SOKO os padrinhos perfeitos para fazer acontecer. Um projeto feito pela periferia e para a periferia, que coloca a Farra frente a frente a outros players do mercado digital, sempre com excelência em produção e propósito!', 'published', '{"order":83,"image":"https://bucket.farra.media/gp.png","language":"ptbr","slug":"gastronomia-periferica-continental","videos":["https://vimeo.com/720732573","https://vimeo.com/720737430","https://vimeo.com/720742041","https://vimeo.com/720745540","https://vimeo.com/720754306","https://vimeo.com/720765824","https://vimeo.com/733744331"],"videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Produ\u00e7\u00e3o Executiva","content":"Gui Vieira"},{"title":"Gerente de Projetos","content":"Yasmin Persi"},{"title":"Coordena\u00e7\u00e3o de Produ\u00e7\u00e3o","content":"Tarcila Vila"},{"title":"Roteiro","content":"Sergio Barbosa e L\u00e9o Parron"},{"title":"Produ\u00e7\u00e3o e Cria\u00e7\u00e3o","content":"Farra"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"06d474c0-842c-4e68-9980-6cace48fd908","legacy_posttype":"jobs","post_thumbnail_id":"479"}', 1716476838000, 1716476838000, 1726862744561);
