INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (488, 15, NULL, NULL, 39, 'Interrogatório com Kevin - Elite | Netflix', 'interrogatorio-com-kevin-elite-netflix-en-us', NULL, 'Film and series releases for Netflix with completely different plots and proposals: “El Camino”, a Breaking Bad film with Maurício Meirelles included in the self-help group; “Elite”, with MC Kevinho, where we recreated the murdered man’s party and included Kevinho in the deposition room with the series’ police chief; “Eu Resolvi Esperar”, a campaign with Sandy for the launch of the second season of La Casa de Papel; “The Crown”, with the participation of Queen Elza Soares; and “Roma”, to promote Alfonso Cuarón’s Oscar-winning film.', 'published', '{"order":11,"image":"https://bucket.farra.media/E.png","language":"enUS","slug":"interrogatorio-com-kevin-elite-netflix","videos":"https://vimeo.com/605942768","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Executive Producer:","content":"Gui Vieira "}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"2345c486-baaf-47f2-8f8f-7dcf5b58c9b6","legacy_posttype":"jobs","post_thumbnail_id":"487"}', 1727798732000, 1727798732000, 1727798769989);
