INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (490, 15, NULL, NULL, 41, 'Interrogatório com Kevin - Elite | Netflix', 'interrogatorio-com-kevin-elite-netflix-pt-br', NULL, 'Lançamentos de filmes e séries para Netflix com enredos e propostas totalmente distintas: “El Camino”, um filme de Breaking Bad com Maurício Meirelles inserido no grupo de autoajuda; “Elite”, com MC Kevinho, onde refizemos a festa do assassinado e incluímos Kevinho na sala de depoimento com a delegada da série; “Eu Resolvi Esperar”, campanha com Sandy para lançamento da segunda temporada de La Casa de Papel; “The Crown”, com participação da rainha Elza Soares; e “Roma”, para promoção do filme de Alfonso Cuarón, vencedor do Oscar.', 'published', '{"order":12,"image":"https://bucket.farra.media/E.png","language":"ptbr","slug":"interrogatorio-com-kevin-elite-netflix","videos":"https://vimeo.com/605942768","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Produ\u00e7\u00e3o Executiva:","content":"Gui Vieira "}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"44cc4bf0-917a-495b-bbba-2b8fc2d4d8bd","legacy_posttype":"jobs","post_thumbnail_id":"489"}', 1727311560000, 1727311560000, 1727311728815);
