INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (492, 15, NULL, NULL, 39, 'Já Fui Você | NATURA + MiBR', 'ja-fui-voce-natura-mibr-en-us', NULL, 'Vitorinha and MIBR present “Já Fui Você”. A music video that marks the debut of the artist as an influencer of Made In Brazil and also as an ambassador of Natura alongside Yulla and Athena, reinforcing MIBR’s position on inclusion and diversity, in addition to announcing Natura as the main sponsor of the Valorant and League of Legends inclusive lines.', 'published', '{"order":83,"image":"https://bucket.farra.media/mibr2.png","language":"enUS","slug":"ja-fui-voce-natura-mibr","videos":"https://vimeo.com/844339034","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Direction","content":"Gui Cintra e Mateus Rigola"},{"title":"Writing","content":"Rodrigo Moura e L\u00e9o Parron"},{"title":"Executive Production","content":"Gui Vieira e Tayna Adam"},{"title":"Productin Manager","content":"Ju Hodas"},{"title":"Post-production Coordinator","content":"Fred Kesselring"},{"title":"Editing","content":"Lucas Ara\u00fajo"},{"title":"Social Media","content":"Bruna Garcia"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"b09d277c-007c-4d1d-98b9-eb9544908986","legacy_posttype":"jobs","post_thumbnail_id":"491"}', 1719709099000, 1719709099000, 1727792266026);
