INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (494, 15, NULL, NULL, 41, 'Já fui Você | NATURA + MiBR', 'ja-fui-voce-natura-mibr-pt-br', NULL, 'Vitorinha e MIBR apresentam “Já Fui Você”. Um clipe musical que marca a chegada da artista como influenciadora do Made In Brazil e também como embaixadora da Natura dentro da org ao lado de Yulla e Athena, reforçando o posicionamento do MIBR sobre inclusão e diversidade, além de anunciar a Natura como patrocinadora principal das lines de Valorant e League of Legends inclusivas.', 'published', '{"order":84,"image":"https://bucket.farra.media/mibr2.png","language":"ptbr","slug":"ja-fui-voce-natura-mibr","videos":"https://vimeo.com/844339034","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Dire\u00e7\u00e3o","content":"Gui Cintra e Mateus Rigola"},{"title":"Roteiro","content":"Rodrigo Moura e L\u00e9o Parron"},{"title":"Produ\u00e7\u00e3o Executiva","content":"Gui Vieira e Tayna Adam"},{"title":"Dire\u00e7\u00e3o de Produ\u00e7\u00e3o","content":"Ju Hodas"},{"title":"Finaliza\u00e7\u00e3o","content":"Fred Kesselring"},{"title":"Montagem","content":"Lucas Ara\u00fajo"},{"title":"Social Media","content":"Bruna Garcia"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"5fdec804-89dc-467a-85ce-16c9d2dd0ec0","legacy_posttype":"jobs","post_thumbnail_id":"493"}', 1716476900000, 1716476900000, 1726845319448);
