INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (500, 15, NULL, NULL, 39, 'Knuckles | Paramount +', 'knuckles-paramount-en-us', NULL, 'Paramount+ sought Farra to create promotional materials for the upcoming series Knuckles on the streaming platform. Farra developed this campaign featuring Kleber Bambam interacting with the animated character from the film, using the original lines and recreating the scene where the original actor interacts with Knuckles, inserting Bambam into the scene. We scripted the interactions to give a new meaning to the dialogue. The text incorporates recent elements that went viral on social media, where Bambam lost a boxing match to Popó in just 30 seconds, with Knuckles taking on the role of his new trainer.', 'published', '{"order":90,"image":"https://bucket.farra.media/knuckles.png","language":"enUS","slug":"knuckles-paramount","videos":"https://vimeo.com/943799938","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Production:","content":"Farra"},{"title":"Direction: ","content":"Gui Cintra"},{"title":"Executive Production:","content":"Gui Vieira e Tayna Adam"},{"title":"Project Management:","content":"Rosa Taques"},{"title":"Direction Production:","content":"Ju Hodas"},{"title":"Editor:","content":"Mike Prado"},{"title":"Audio:","content":"Dream Box"},{"title":"Motion:","content":"S\u00e9rgio Dimi"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"ce8eee97-081a-43cd-a78a-81ec85c556eb","legacy_posttype":"jobs","post_thumbnail_id":"499"}', 1726764206000, 1726764206000, 1727791719568);
