INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (502, 15, NULL, NULL, 41, 'Knuckles | Paramount +', 'knuckles-paramount-pt-br', NULL, 'A Paramount+ buscou a agência de entretenimento Farra para criar peças para divulgação da nova série Knuckles que estava para estrear no Streaming. A Farra criou essa ação com Kleber Bambam interagindo com o personagem animado do Filmado, usando as falas originais e recriando a cena onde o ator original interage com Knuckles e inserindo Bambam na cena, roteirizamos as interações para dar outro sentido ao diálogo. O texto trás elementos recentes que viralizaram nas redes sociais onde Bambam perdeu uma luta com Popó em apenas 30 segundos e Knuckles assume o papel de seu novo treinador.', 'published', '{"order":93,"image":"https://bucket.farra.media/knuckles.png","language":"ptbr","slug":"knuckles-paramount","videos":"https://vimeo.com/943799938","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Produ\u00e7\u00e3o:","content":"Farra"},{"title":"Dire\u00e7\u00e3o: ","content":"Gui Cintra"},{"title":"Produ\u00e7\u00e3o Executiva:","content":"Gui Vieira e Tayna Adam"},{"title":"Gest\u00e3o de Projeto:","content":"Rosa Taques"},{"title":"Diretora de Produ\u00e7\u00e3o:","content":"Ju Hodas"},{"title":"Montagem:","content":"Mike Prado"},{"title":"\u00c1udio:","content":"Dream Box"},{"title":"Motion e Finaliza\u00e7\u00e3o:","content":"S\u00e9rgio Dimi"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"5f9602f8-648f-431c-856f-e808db18143e","legacy_posttype":"jobs","post_thumbnail_id":"501"}', 1727791608023, 1727791608023, 1727791608023);
