INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (508, 15, NULL, NULL, 41, 'Lançamento Lightyear | Disney', 'lancamento-lightyear-disney-pt-br', NULL, 'Campanha de lançamento para o filme Lightyear que a Farra criou, roteirizou e produziu para a Disney/Pixar.Foram feitos 2 filmes de divulgação que contaram com as participações dos dubladores dos Buzz Lightyears: Marcos Mion e Guilherme Briggs. O filme hero foi ao ar durante o intervalo do BBB22, também conhecido como Super Bowl brasileiro.', 'published', '{"order":106,"image":"https://bucket.farra.media/lightyear.png","language":"ptbr","slug":"lancamento-lightyear-disney","videos":["https://vimeo.com/703898544","https://vimeo.com/704148968"],"videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Produ\u00e7\u00e3o Executiva","content":"Gui Vieira e Tarcila Villa"},{"title":"Dire\u00e7\u00e3o","content":"Gui Cintra"},{"title":"Diretora de Produ\u00e7\u00e3o","content":"Juliana Hodas"},{"title":"Roteiro","content":"Andr\u00e9 Brandt, L\u00e9o Parron e Maria Clara Lucci"},{"title":"Produ\u00e7\u00e3o e Cria\u00e7\u00e3o","content":"Farra"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"82b9a2fc-7558-4e6f-8c98-0d8810343311","legacy_posttype":"jobs","post_thumbnail_id":"507"}', 1716465401000, 1716465401000, 1767703350106);
