INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (510, 15, NULL, NULL, 41, 'Lançamento Luca | Disney+', 'lancamento-luca-disney-pt-br', NULL, 'A Farra criou, roteirizou e produziu as peças da campanha audiovisual do lançamento do filme Luca, da Disney/Pixar, com estreia exclusiva no Disney+. Foram 4 ações distintas: uma série de peças e fotos para divulgação para imprensa com entrevistas e peças para o digital com os dubladores do filme Luis Miranda, Claudia Raia e Sophia Raia; uma esquete de comédia com Luis, Claudia e Sophia; uma live com Dani Calabresa para divulgação no dia do lançamento do filme; uma websérie com o lado italianissimo de Dani Calabresa para divulgação em suas redes.', 'published', '{"order":86,"image":"https://bucket.farra.media/lucca.png","language":"ptbr","slug":"lancamento-luca-disney","videos":["https://vimeo.com/558223465","https://vimeo.com/569538333","https://vimeo.com/569549244"],"videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Dire\u00e7\u00e3o","content":"Gui Cintra"},{"title":"Produ\u00e7\u00e3o Executiva","content":"Guilherme Vieira"},{"title":"Diretora de Produ\u00e7\u00e3o","content":"Tarcila Villa"},{"title":"Roteiro","content":"Andr\u00e9 Brandt, Sergio Barbosa, Rodrigo Moura e Gui Cintra"},{"title":"Produ\u00e7\u00e3o e Cria\u00e7\u00e3o","content":"Farra"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"8e880055-569d-4d4f-9208-828377f60ff2","legacy_posttype":"jobs","images":"[\"https://bucket.farra.media/3613323-claudia-raia-contou-que-sophia-comeca-a-950x0-2.jpg\",\"https://bucket.farra.media/3613332-o-filme-lucca-tem-claudia-raia-sophia-950x0-2.jpg\"]","post_thumbnail_id":"509"}', 1716423025000, 1716423025000, 1726845023464);
