INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (512, 15, NULL, NULL, 41, 'Lançamento Um Cavaleiro em Moscou | Paramount +', 'lancamento-um-cavaleiro-em-moscou-paramount-pt-br', NULL, 'A Paramount+ buscou a agência de entretenimento Farra para criar peças para divulgação da nova série "Um Cavalheiro em Moscou".  Na série um Conde interpretado por Ewan Mcgregor é condenado a passar o resto de sua vida preso dentro de um hotel. No filme promocional buscamos a figura do conde mais famoso Brasileiro, Chiquinho Scarpa, para ilustrar como seria sua vida se estivesse condenado a viver preso em sua mansão.', 'published', '{"order":72,"image":"https://bucket.farra.media/Chiqi.png","language":"ptbr","slug":"lancamento-um-cavaleiro-em-moscou-paramount","videos":["https://vimeo.com/976620307","https://vimeo.com/976620201"],"videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Dire\u00e7\u00e3o:","content":"Gui Cintra"},{"title":"Produ\u00e7\u00e3o:","content":"Farra"},{"title":"Edi\u00e7\u00e3o: ","content":"Mike Prado"},{"title":"Dire\u00e7\u00e3o de Arte:","content":"Bia Vidal"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"97f64bce-2021-40b6-b062-fb3b83158995","legacy_posttype":"jobs","post_thumbnail_id":"511"}', 1726765351000, 1726765351000, 1726846959061);
