INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (514, 15, NULL, NULL, 41, 'Lançamento | STAR+', 'lancamento-star-pt-br', NULL, 'O Streaming Star + chegou ao Brasil e a Farra foi escolhida para criar e executar uma campanha com uma grande gama de influenciadores do mercado, Vitor Fernando, Pocah, Sophia Abrahao, Sergio Malheiros, Lucas Guedes, John Drops, Bia e Branca.Criação, roteiro, produção e pós produção Farra, com a troca criativa e indicações de execução para os Creators, apoiando os valores da marca sem perder a espontaneidade de cada Creator. A campanha entregou 10 Reels diferentes e mais de 120 stories do conteúdo Star +.', 'published', '{"order":27,"image":"https://bucket.farra.media/star.avif","language":"ptbr","slug":"lancamento-star","videos":"https://vimeo.com/623638191","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Produ\u00e7\u00e3o Executiva","content":"Guilherme Vieira"},{"title":"Produtoras","content":"Tarcila Villa e Yasmin Persi"},{"title":"Roteiro","content":"Andr\u00e9 Brandt, Maria Clara, Sergio Barbosa e Gui Cintra"},{"title":"Dire\u00e7\u00e3o","content":"Gui Cintra"},{"title":"Produ\u00e7\u00e3o","content":"Farra"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"184cc700-fe9f-4ce6-9418-31c3e0edd558","legacy_posttype":"jobs","post_thumbnail_id":"513"}', 1716421601000, 1716421601000, 1727310153372);
