INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (516, 15, NULL, NULL, 41, 'Lançamentos | Netflix', 'lancamentos-netflix-pt-br', NULL, 'Lançamentos de filmes e séries para Netflix com enredos e propostas totalmente distintas: “El Camino”, um filme de Breaking Bad com Maurício Meirelles inserido no grupo de autoajuda; “Elite”, com MC Kevinho, onde refizemos a festa do assassinado e incluímos Kevinho na sala de depoimento com a delegada da série; “Eu Resolvi Esperar”, campanha com Sandy para lançamento da segunda temporada de La Casa de Papel; “The Crown”, com participação da rainha Elza Soares; e “Roma”, para promoção do filme de Alfonso Cuarón, vencedor do Oscar.', 'published', '{"order":3,"image":"https://bucket.farra.media/lancamentos.png","language":"ptbr","slug":"lancamentos-netflix","videos":["https://vimeo.com/545673202","https://vimeo.com/605942768","https://vimeo.com/545673839","https://vimeo.com/545675365","https://vimeo.com/545665629"],"videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Coord. de Produ\u00e7\u00e3o","content":"Guilherme Vieira"},{"title":"Produtora","content":"Awake Film"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"e1376ec9-8a64-4339-91d6-44a293c7e46a","legacy_posttype":"jobs","post_thumbnail_id":"515"}', 1716420031000, 1716420031000, 1727799310749);
