INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (522, 15, NULL, NULL, 39, 'Luca Special | Disney', 'luca-special-disney-en-us', NULL, 'Farra created, wrote the script and produced the pieces for the audiovisual campaign for the launch of the Disney/Pixar film Luca. There were 4 different actions: a series of pieces and photos for press release with interviews and digital pieces with the film''s voice actors Luís Miranda, Claudia Raia and Sophia Raia; a comedy sketch with Luís, Claudia and Sophia; a live broadcast with Dani Calabresa for release on the day of the film''s release; a web series with Dani Calabresa''s very Italian side for release on its social networks.', 'published', '{"order":78,"image":"https://bucket.farra.media/K.png","language":"enUS","slug":"luca-special-disney","videos":"https://vimeo.com/569549244","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Production:","content":"Farra"},{"title":"Direction:","content":"Gui Cintra"},{"title":"Writing:","content":"Andr\u00e9 Brandt"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"3bdae9d6-7be6-4343-8d90-1b53efd62a7f","legacy_posttype":"jobs","post_thumbnail_id":"521"}', 1726846094000, 1726846094000, 1727792544653);
