INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (524, 15, NULL, NULL, 39, 'Mais Vividas | Molico', 'mais-vividas-molico-en-us', NULL, 'Development, creation, and production of shows for the "Receitas Nestlé" Channel and Portal, from Nestlé Brazil. In 2019 and 2020, with over 50 episodes of various shows  delivered for the brand''s channel in different formats: reality, talk-show, documentary, culinary, etc. Among the formats, standout titles include: Chocolateria, Põe Cremosidade Nisso, Deu Ruim, Nutri Ajuda, Brasil Sabores Mil, Receitas de Final de Semana, Mais Vividas, and Escolhas Certas. Under the "Receitas Nestlé" umbrella, the brands Molico, Maggi, Garoto, Nutren, Nestlé Cream, Nestlé Oats, Leite Moça, Nescafé, and Nestlé Health Science were represented.', 'published', '{"order":49,"image":"https://bucket.farra.media/m.png","language":"enUS","slug":"mais-vividas-molico","videos":"https://vimeo.com/586429601","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Executive Production:","content":"Gui Vieira "},{"title":"Production:","content":"Awake Film"},{"title":"Direction Production:","content":"Tarcila Villa"},{"title":"Writing and creation:","content":"Gui Cintra, Andr\u00e9 Brandt e Dani Guti"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"4d3f90c7-4a1d-4353-9efc-a1c174c7f5f2","legacy_posttype":"jobs","post_thumbnail_id":"523"}', 1727187030000, 1727187030000, 1727795909101);
