INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (526, 15, NULL, NULL, 41, 'Mais Vividas | Molico', 'mais-vividas-molico-pt-br', NULL, 'Desenvolvimento, criação e produção de programas para o Canal e Portal “Receitas Nestlé”, da Nestlé Brasil. Em 2019 e 2020, foram entregues mais de 50 episódios de diferentes programas para o canal da marca, em diferentes formatos: reality, talk-show, documental, culinário, etc. Dentre os formatos, se destacam títulos como: Chocolateria, Põe Cremosidade Nisso, Deu Ruim, Nutri Ajuda, Brasil Sabores Mil, Receitas de Final de Semana, Mais Vividas e Escolhas Certas. No guarda chuva de Receitas Nestlé, foram atendidas as marcas Molico, Maggi, Garoto, Nutren, Creme de Leite Nestlé, Aveias Nestlé, Leite Moça, Nescafé, Nestlé Health Science.', 'published', '{"order":50,"image":"https://bucket.farra.media/m.png","language":"ptbr","slug":"mais-vividas-molico","videos":"https://vimeo.com/586429601","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Produ\u00e7\u00e3o:","content":"Gui Vieira "},{"title":"Produ\u00e7\u00e3o:","content":"Awake Film"},{"title":"Dire\u00e7\u00e3o de Produ\u00e7\u00e3o:","content":"Tarcila Villa"},{"title":"Roteiro e Cria\u00e7\u00e3o:","content":"Gui Cintra, Andr\u00e9 Brandt e Dani Guti"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"99dc63dd-fd16-4ca9-a26c-01537a4671f2","legacy_posttype":"jobs","post_thumbnail_id":"525"}', 1727795242696, 1727795242696, 1727795242696);
