INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (536, 15, NULL, NULL, 39, 'Mil e Uma Tretas | Videocast', 'mil-e-uma-tretas-videocast-en-us', NULL, 'Farra created and produced the videocast Mil e Uma Tretas, which addresses an exchange of ideas about motherhood without beating around the bush or romanticism, with best friends – or rather, “husbands”, as they joke – Julia Faria and Thaila Ayala. In addition, a team of guests joins in and brings their experiences and stories to light. A sincere and light-hearted meeting, where motherhood is discussed in a unique way!', 'published', '{"order":25,"image":"https://bucket.farra.media/mil-e-uma.png","language":"enUS","slug":"mil-e-uma-tretas-videocast","videos":"https://vimeo.com/863259418","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Starring:","content":"Julia Faria e Thaila Ayala"},{"title":"Writing:","content":"Stephanie Marques e Leo Parron"},{"title":"Project Manager:","content":"Rosa Taques"},{"title":"Direction Production:","content":"Ju Hodas"},{"title":"Executive Production:","content":"Gui Vieira e Tayna Adam"},{"title":"Direction:","content":"Bruna Marchi"},{"title":"Casting","content":"Tati Soares e Larissa Salles"},{"title":"Social Media","content":"Bruna Garcia"},{"title":"Post-Production","content":"Lucas Nascimento e  Fred Kesselring"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"9868df32-8314-4f09-b7c0-8b6539da2840","legacy_posttype":"jobs","post_thumbnail_id":"535"}', 1727797559000, 1727797559000, 1727797666293);
