INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (538, 15, NULL, NULL, 41, 'Mil e Uma Tretas | Videocast', 'mil-e-uma-tretas-videocast-pt-br', NULL, 'A Farra criou e produziu para o videocast Mil e Uma Tretas, que aborda uma troca de ideias sobre a maternidade sem rodeios e sem romantismo, com as melhores amigas – ou melhor, “maridas”, como elas brincam – Julia Faria e Thaila Ayala. Além disso, um time de convidados entra na jogada e traz à tona suas experiências e histórias.Um encontro sincero e leve, onde a maternidade é discutida de um jeito único!', 'published', '{"order":26,"image":"https://bucket.farra.media/mil-e-uma.png","language":"ptbr","slug":"mil-e-uma-tretas-videocast","videos":"https://vimeo.com/863259418","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Apresenta\u00e7\u00e3o","content":"Julia Faria e Thaila Ayala"},{"title":"Roteiro","content":"Stephanie Marques e Leo Parron"},{"title":"Gest\u00e3o de Projeto","content":"Rosa Taques"},{"title":"Dire\u00e7\u00e3o de Produ\u00e7\u00e3o","content":"Ju Hodas"},{"title":"Produ\u00e7\u00e3o Executiva","content":"Gui Vieira e Tayna Adam"},{"title":"Dire\u00e7\u00e3o","content":"Bruna Marchi"},{"title":"Casting","content":"Tati Soares e Larissa Salles"},{"title":"M\u00eddias Sociais","content":"Bruna Garcia"},{"title":"P\u00f3s Produ\u00e7\u00e3o","content":"Lucas Nascimento e  Fred Kesselring"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"01d36926-85cf-41f9-9ce4-68eacd7fefd5","legacy_posttype":"jobs","post_thumbnail_id":"537"}', 1716479140000, 1716479140000, 1727310248626);
