INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (550, 15, NULL, NULL, 41, 'Más Bueno. Más Breyers | Breyers', 'mas-bueno-mas-breyers-breyers-pt-br', NULL, 'A Farra foi convidada pela Breyers pra fazer uma campanha digital voltada para o mercado internacional! Junto com o time da agência TAG, criamos e produzimos 8 conteúdos em vídeo e também os KVs da marca em uma diária que deixou todo mundo com água na boca.', 'published', '{"order":76,"image":"https://bucket.farra.media/breyers.png","language":"ptbr","slug":"mas-bueno-mas-breyers-breyers","videos":["https://vimeo.com/813594724","https://vimeo.com/813635029","https://vimeo.com/813594054","https://vimeo.com/813592258"],"videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Produ\u00e7\u00e3o Executiva","content":"Gui Vieira e Tayna Adam"},{"title":"Produ\u00e7\u00e3o Art\u00edstica","content":"Tati Soares"},{"title":"Roteiro e dire\u00e7\u00e3o","content":"L\u00e9o Parron"},{"title":"P\u00f3s Produ\u00e7\u00e3o","content":"Fred Kesselring"},{"title":"Coordena\u00e7\u00e3o de Produ\u00e7\u00e3o","content":"Ju Hodas"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"1a1cdf65-11dc-42db-a679-3ce833ffe698","legacy_posttype":"jobs","post_thumbnail_id":"549"}', 1716465395000, 1716465395000, 1726846586214);
