INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (554, 15, NULL, NULL, 39, 'Nestatueta de Ouro | Nescau', 'nestatueta-de-ouro-nescau-en-us', NULL, 'Creation and production of a series of formats to meet internal communication needs during the pandemic. How to make a virtual and audiovisual impact with the same effectiveness as traditional large physical events? The answer was a series of  different genres shows, filled with entertainment, information, and humor, featuring prominent names from the national comedy scene, such as Maurício Meirelles, Miá Mello, and Daniel Zukerman.', 'published', '{"order":32,"image":"https://bucket.farra.media/b.png","language":"enUS","slug":"nestatueta-de-ouro-nescau","videos":"https://vimeo.com/585911802","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Production:","content":"Awake Film"},{"title":"Executive Production:","content":"Gui Vieira "},{"title":"Direction Production:","content":"Tarcila Villa"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"ab475933-6aec-43d8-9738-b347e5cb488f","legacy_posttype":"jobs","post_thumbnail_id":"553"}', 1727796872000, 1727796872000, 1727796914279);
