INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (556, 15, NULL, NULL, 41, 'Nestatueta de Ouro | Nescau', 'nestatueta-de-ouro-nescau-pt-br', NULL, 'Criação e produção de uma série de formatos para atender a necessidades internas de comunicação em tempos de pandemia. Como impactar de maneira virtual e audiovisual com a mesma eficiência dos tradicionais e grandiosos eventos físicos? A resposta foi uma série de programas de gêneros diferentes com muito entretenimento, informação e humor, que contaram com a participação de nomes importantes da comédia nacional, como Maurício Meirelles, Miá Mello e Daniel Zukerman.', 'published', '{"order":32,"image":"https://bucket.farra.media/b.png","language":"ptbr","slug":"nestatueta-de-ouro-nescau","videos":"https://vimeo.com/585911802","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Produ\u00e7\u00e3o:","content":"Awake Film"},{"title":"Produ\u00e7\u00e3o Executiva:","content":"Gui Vieira "},{"title":"Dire\u00e7\u00e3o de Produ\u00e7\u00e3o:","content":"Tarcila Villa"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"f7614423-65eb-415e-a44f-a026bb19f0dc","legacy_posttype":"jobs","post_thumbnail_id":"555"}', 1727268936000, 1727268936000, 1727441610878);
