INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (562, 15, NULL, NULL, 41, 'No Ritmo da Lore', 'no-ritmo-da-lore-pt-br', NULL, 'Produzido pela FARRA, com roteiro e direção de Andre Brandt, essa webserie mostra os bastidores do carnaval da musa da Viradouro, Lore Improta. No decorrer de 6 episódios, vamos acompanhar a escolha dos looks, diárias de gravação, aulas de dança, ensaio de quadra, ensaio de rua e tudo mais que não para e acontece no paralelo. Não perca, toda quinta-feira tem episódio novo lá no YouTube.', 'published', '{"order":109,"image":"https://bucket.farra.media/lore improta.png","language":"ptbr","slug":"no-ritmo-da-lore","videos":"https://vimeo.com/1057547400","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Dire\u00e7\u00e3o e Roteiro:","content":"Andr\u00e9 Brandt"},{"title":"Produ\u00e7\u00e3o:","content":"Farra"},{"title":"Produ\u00e7\u00e3o Executiva:","content":"Gui Vieira e Tayna Adam"},{"title":"Dire\u00e7\u00e3o de Produ\u00e7\u00e3o:","content":"Juliana Hodas"},{"title":"Assist\u00eancia de Produ\u00e7\u00e3o Executiva:","content":" Beatriz Fontana Carvalho"},{"title":"Controladoria:","content":" Andressa Carrijo"},{"title":"Design:","content":"Beatriz Vidal"},{"title":"Controladoria:","content":"Andressa Carrijo"},{"title":"Motion Design:","content":"Serginho Dimi"},{"title":"Dire\u00e7\u00e3o de Fotografia: ","content":"Alex Tavares"},{"title":"Filmmaker Rio de Janeiro: ","content":"Miguel Souza"},{"title":"Filmmaker Salvador: ","content":"Tarcisio Sampaio"},{"title":"Edi\u00e7\u00e3o: ","content":"Mike Lopes Prado"},{"title":"Coordena\u00e7\u00e3o de p\u00f3s-produ\u00e7\u00e3o: ","content":"Frederico Kesselring"},{"title":"Filmmaker S\u00e3o Paulo: ","content":"Victor Lima"},{"title":"Produ\u00e7\u00e3o de\u00a0\u00c1udio:\u00a0","content":"DreamBox"},{"title":"Colorista: ","content":"Gabriel Ranzani"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"850d4766-7d11-4295-b524-9a63c18c24de","legacy_posttype":"jobs","post_thumbnail_id":"561"}', 1739790091000, 1739790091000, 1767788304794);
