INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (564, 15, NULL, NULL, 39, 'Nutri Ajuda | Nutren', 'nutri-ajuda-nutren-en-us', NULL, 'Development, creation, and production of shows for the "Receitas Nestlé" Channel and Portal, from Nestlé Brazil. In 2019 and 2020, with over 50 episodes of various shows  delivered for the brand''s channel in different formats: reality, talk-show, documentary, culinary, etc. Among the formats, standout titles include: Chocolateria, Põe Cremosidade Nisso, Deu Ruim, Nutri Ajuda, Brasil Sabores Mil, Receitas de Final de Semana, Mais Vividas, and Escolhas Certas. Under the "Receitas Nestlé" umbrella, the brands Molico, Maggi, Garoto, Nutren, Nestlé Cream, Nestlé Oats, Leite Moça, Nescafé, and Nestlé Health Science were represented.', 'published', '{"order":46,"image":"https://bucket.farra.media/6.png","language":"enUS","slug":"nutri-ajuda-nutren","videos":["https://vimeo.com/557763188","https://vimeo.com/582595519"],"videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Production:","content":"Awake Film"},{"title":"Executive Production:","content":"Gui Vieira "},{"title":"Direction Production:","content":"Tarcila Villa"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"29e31a8e-22b1-4786-9347-af3e87e8035a","legacy_posttype":"jobs","post_thumbnail_id":"563"}', 1727795425000, 1727795425000, 1727796007071);
