INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (566, 15, NULL, NULL, 41, 'Nutri Ajuda | Nutren', 'nutri-ajuda-nutren-pt-br', NULL, 'Desenvolvimento, criação e produção de programas para o Canal e Portal “Receitas Nestlé”, da Nestlé Brasil. Em 2019 e 2020, foram entregues mais de 50 episódios de diferentes programas para o canal da marca, em diferentes formatos: reality, talk-show, documental, culinário, etc. Dentre os formatos, se destacam títulos como: Chocolateria, Põe Cremosidade Nisso, Deu Ruim, Nutri Ajuda, Brasil Sabores Mil, Receitas de Final de Semana, Mais Vividas e Escolhas Certas. No guarda chuva de Receitas Nestlé, foram atendidas as marcas Molico, Maggi, Garoto, Nutren, Creme de Leite Nestlé, Aveias Nestlé, Leite Moça, Nescafé, Nestlé Health Science.', 'published', '{"order":47,"image":"https://bucket.farra.media/6.png","language":"ptbr","slug":"nutri-ajuda-nutren","videos":["https://vimeo.com/557763188","https://vimeo.com/582595519"],"videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Produ\u00e7\u00e3o:","content":"Awake Film"},{"title":"Produ\u00e7\u00e3o Executiva:","content":"Gui Vieira "},{"title":"Dire\u00e7\u00e3o de Produ\u00e7\u00e3o:","content":"Tarcila Villa"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"23c88f8a-f40a-496f-805f-55e1d65c1793","legacy_posttype":"jobs","post_thumbnail_id":"565"}', 1727208597000, 1727208597000, 1727358057188);
