INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (570, 15, NULL, NULL, 41, 'O Maior Rótulo do Mundo | Heinz', 'o-maior-rotulo-do-mundo-heinz-pt-br', NULL, 'Heinz fez uma ação com o maior rótulo do mundo, para mostrar os ingredientes do produto que estampavam a frente do rótulo. Era pra ser só um simples making of da ação, mas virou um mega videocase.', 'published', '{"order":7,"image":"https://bucket.farra.media/heinz-1.png","language":"ptbr","slug":"o-maior-rotulo-do-mundo-heinz","videos":"https://vimeo.com/545666496","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"cce6ee8a-7d56-4900-86cf-ec9d7d50d9bc","legacy_posttype":"jobs","images":"[\"https://bucket.farra.media/01.jpg\"]","post_thumbnail_id":"569"}', 1716419430000, 1716419430000, 1727312567069);
