INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (572, 15, NULL, NULL, 41, 'O Poder da Escolha | Rennova', 'o-poder-da-escolha-rennova-pt-br', NULL, 'A Farra foi a produtora responsável pelo roteiro e pela produção da peça publicitária para a marca Rennova, uma linha de produtos para procedimentos estéticos injetáveis que sublinha a importância de escolher o bem-estar. E essa produção contou com a participação das embaixadoras Giovanna Antonelli e Deborah Secco! Foi um projeto ambicioso e desafiador. A Farra, em parceria e sinergia com a Rennova, criou e produziu esse filme, que foi gravado no Rio de Janeiro e adaptado tanto para exibição na TV quanto para veiculação na internet, além de conteúdos para a Landing Page da marca, proporcionando uma experiência envolvente para o público-alvo da Rennova.', 'published', '{"order":99,"image":"https://bucket.farra.media/rennova-1.png","language":"ptbr","slug":"o-poder-da-escolha-rennova","videos":"https://vimeo.com/869568669","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Cria\u00e7\u00e3o","content":"Andr\u00e9 Brandt, S\u00e9rgio Barbosa e Rodrigo Moura"},{"title":"Dire\u00e7\u00e3o","content":"Hugo Moura"},{"title":"Diretora de Produ\u00e7\u00e3o","content":"Juliana Hodas"},{"title":"Produ\u00e7\u00e3o Executiva","content":"Gui Vieira e Tayna Adam"},{"title":"Produ\u00e7\u00e3o","content":"Farra"},{"title":"Montador","content":"Lucas Araujo"},{"title":"Coordena\u00e7\u00e3o de P\u00f3s Produ\u00e7\u00e3o","content":"Fred Kesselring"},{"title":"Dire\u00e7\u00e3o de Produ\u00e7\u00e3o","content":"Ju Hodas"},{"title":"Assistente de Produ\u00e7\u00e3o Executiva","content":"Beatriz Fontana"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"af0bff77-35d3-4342-9e48-d5822b662cf0","legacy_posttype":"jobs","post_thumbnail_id":"571"}', 1727790597000, 1727790597000, 