INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (582, 15, NULL, NULL, 41, 'PIX | Itaú', 'pix-itau-pt-br', NULL, 'No final de 2024 roteirizamos uma série de vídeos para o perfil do TikTok do Itaú, onde senhoras da terceira idade contam de maneira bem humorada suas experiências de final do ano, todas elas relacionadas às  ferramentas de Pix do banco. O intuito das peças, além de entreter com as suas curtas histórias de diversas "vovós" do Brasil, foi demonstrar as funções e novidades de Pix presentes no app do Itaú.No final de 2024 roteirizamos uma série de vídeos para o perfil do TikTok do Itaú, onde senhoras da terceira idade contam de maneira bem humorada suas experiências de final do ano, todas elas relacionadas às  ferramentas de Pix do banco. O intuito das peças, além de entreter com as suas curtas histórias de diversas "vovós" do Brasil, foi demonstrar as funções e novidades de Pix presentes no app do Itaú.', 'published', '{"order":91,"image":"https://bucket.farra.media/itau.png","language":"ptbr","slug":"pix-itau","videos":["https://vimeo.com/1047245424","https://vimeo.com/1047245404","https://vimeo.com/1047244372","https://vimeo.com/1047245371"],"videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Roteiro:","content":"S\u00e9rgio Barbosa"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"ac75b649-e59f-4810-9dad-f82968e9e5e7","legacy_posttype":"jobs","post_thumbnail_id":"581"}', 1739807170000, 1739807170000, 1741720812039);
