INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (600, 15, NULL, NULL, 39, 'Posso Mandar Áudio? | Globoplay', 'posso-mandar-audio-globoplay-en-us', NULL, 'A bad date is not just to be lived, but to be shared! When one of us has a bad date, we’re all embarrassed together – and celebrities are no different. Honestly, you needed a podcast to make last week’s trash boy look like a prince. Or something like that. “Posso Mandar Áudio?”, new episodes every Wednesday, available for free on gshow, Globoplay and all audio platforms.', 'published', '{"order":93,"image":"https://bucket.farra.media/pma-2.png","language":"enUS","slug":"posso-mandar-audio-globoplay","videos":"https://vimeo.com/702107279","videosHome":["https://vimeo.com/702107279"],"videosHomeOrder":null,"fichaTecnica":[{"title":"Starring","content":"Dani Calabresa"},{"title":"Direction","content":"Andr\u00e9 Brandt"},{"title":"Writing","content":"Ste Marques"},{"title":"Editing","content":"Lucas Ara\u00fajo"},{"title":"Finishing","content":"Mandril A\u00fadio"},{"title":"Production","content":"Farra"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"50766bbc-226d-41fc-b676-9919c62c185d","legacy_posttype":"jobs","post_thumbnail_id":"599"}', 1719709158000, 1719709158000, 1727799468539);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (601, 6, NULL, NULL, NULL, 'pma-2.png', 'attachment-jobs-posso-mandar-audio-globoplay-pt-br', NULL, NULL, 'published', '{"show_in_menu":false,"menu_options":[],"icon":"line-md:file","mime_type":"image/png","attachment_file":"pma-2.png","attachment_path":"https://bucket.farra.media/pma-2.png","attachment_alt":"Posso Mandar \u00c1udio? | Globoplay"}', NULL, 1716478458000, 1767703241796);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (602, 15, NULL, NULL, 41, 'Posso Mandar Áudio? | Globoplay', 'posso-mandar-audio-globoplay-pt-br', NULL, 'Date ruim não é só para ser vivido, mas para ser compartilhado! Quando um de nós tem um date ruim, todos passamos vergonha juntos- e com os famosos não é diferente. Fala a verdade, você precisava de um podcast para fazer o boy lixo da semana passada parecer um príncipe. Ou tipo isso. Posso mandar aúdio?, novos episódios toda quarta-feira, disponível grátis no gshow, globolay e todas as plataformas de aúdio.', 'published', '{"order":97,"image":"https://bucket.farra.media/pma-2.png","language":"ptbr","slug":"posso-mandar-audio-globoplay","videos":["https://vimeo.com/702107279","https://vimeo.com/745183504","https://vimeo.com/894655385"],"videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Apresenta\u00e7\u00e3o","content":"Dani Calabresa"},{"title":"Dire\u00e7\u00e3o","content":"Andr\u00e9 Brandt"},{"title":"Roteiro","content":"Ste Marques"},{"title":"Edi\u00e7\u00e3o","content":"Lucas Ara\u00fajo"},{"title":"Finaliza\u00e7\u00e3o","content":"Mandril A\u00fadio"},{"title":"Produ\u00e7\u00e3o","content":"Farra"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"a2cc83f5-3606-40a4-b618-a9c5bc2a352b","legacy_posttype":"jobs","post_thumbnail_id":"601"}', 1716478458000, 1716478458000, 1767703241796);
