INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (608, 15, NULL, NULL, 39, 'Projeto Upload | CNN BRASIL', 'projeto-upload-cnn-brasil-en-us', NULL, 'CNN sought us out to develop the second season of PROJETO UPLOAD, the channel’s futurology show, hosted by Stephanie Fleury. FARRA was the production company responsible for repackaging the show and executing the research, writing, production and whole post-production. Just the way we like it: Involved from creation till broadcasting. Ten 45-minute episodes were shot across 20 days of recording, going through the most various themes with over 50 interviewees.', 'published', '{"order":86,"image":"https://bucket.farra.media/cnn.png","language":"enUS","slug":"projeto-upload-cnn-brasil","videos":"https://vimeo.com/765869003","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Executive Production","content":"Gui Vieira e Tarcila Villa"},{"title":"Direction","content":"Leo Parron"},{"title":"Project Management","content":"Juliana Hodas"},{"title":"Writing","content":"L\u00e9o Parron, S\u00e9rgio Barbosa, Janaina Medeiros"},{"title":"Production","content":"Farra"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"ffcce800-b3e3-4e4b-b010-816ca97d7e5b","legacy_posttype":"jobs","post_thumbnail_id":"607"}', 1719709173000, 1719709173000, 1727792009223);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (609, 6, NULL, NULL, NULL, 'cnn.png', 'attachment-jobs-projeto-upload-cnn-brasil-pt-br', NULL, NULL, 'published', '{"show_in_menu":false,"menu_options":[],"icon":"line-md:file","mime_type":"image/png","attachment_file":"cnn.png","attachment_path":"https://bucket.farra.media/cnn.png","attachment_alt":"Projeto Upload | CNN BRASIL"}', NULL, 1716477068000, 1726844964957);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (610, 15, NULL, NULL, 41, 'Projeto Upload | CNN BRASIL', 'projeto-upload-cnn-brasil-pt-br', NULL, 'CNN nos procurou para desenvolver a segunda temporada do programa PROJETO UPLOAD, programa sobre futurologia do canal apresentado por Stephanie Fleury.A Farra foi a produtora responsável por repaginar o programa e fazer toda a pesquisa, roteiros, produção e pós produção completa. Projeto do jeito que gostamos, da criação a exibição. Foram 10 episódios de 45 minutos cada e 20 diárias de captação sobre os mais variados temas e mais de 50 entrevistados.', 'published', '{"order":87,"image":"https://bucket.farra.media/cnn.png","language":"ptbr","slug":"projeto-upload-cnn-brasil","videos":"https://vimeo.com/765869003","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Produ\u00e7\u00e3o Executiva","content":"Gui Vieira e Tarcila Villa"},{"title":"Dire\u00e7\u00e3o","content":"Leo Parron"},{"title":"Dire\u00e7\u00e3o de Produ\u00e7\u00e3o","content":"Juliana Hodas"},{"title":"Roteiro","content":"L\u00e9o Parron, S\u00e9rgio Barbosa, Janaina Medeiros"},{"title":"Produ\u00e7\u00e3o","content":"Farra"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"5f9c24c7-459f-4256-a102-5de554b74ebf","legacy_posttype":"jobs","post_thumbnail_id":"609"}', 1716477068000, 1716477068000, 1726844964957);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (611, 6, NULL, NULL, NULL, 'pilula de farinha.png', 'attachment-jobs-pilula-de-farinha-o-escandalo-que-gerou-vidas-pt-br', NULL, NULL, 'published', '{"show_in_menu":false,"menu_options":[],"icon":"line-md:file","mime_type":"image/png","attachment_file":"pilula de farinha.png","attachment_path":"https://bucket.farra.media/pilula de farinha.png","attachment_alt":"PÍLULA DE FARINHA - O ESCÂNDALO QUE GEROU VIDAS"}', NULL, 1767707001000, 1767787848941);
INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (612, 15, NULL, NULL, 41, 'PÍLULA DE FARINHA - O ESCÂNDALO QUE GEROU VIDAS', 'pilula-de-farinha-o-escandalo-que-gerou-vidas-pt-br', NULL, 'Co-produção da Farra e Warner Bros , a série documental em três episódios relembra o escândalo de 1998, quando toneladas de placebo do anticoncepcional mais vendido do Brasil chegaram às farmácias, resultando em centenas de gestações indesejadas. Uma história que mistura drama, investigação policial e a busca por justiça, criada por Jana Medeiros e Heddy Fernandes , com direção geral de Cassia Dian e produção executiva de Verônica Villa e Gui Vieira .', 'published', '{"order":112,"image":"https://bucket.farra.media/pilula de farinha.png","language":"ptbr","slug":"pilula-de-farinha-o-escandalo-que-gerou-vidas","videos":"https://vimeo.com/1148044414","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"c018d6ba-1764-4bab-823d-8581a5b6d008","legacy_posttype":"jobs","post_thumbnail_id":"611"}', 1767707001000, 1767707001000, 1767787848941);
