INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (614, 15, NULL, NULL, 39, 'Põe Cremosidade Nisso | Nestlé', 'poe-cremosidade-nisso-nestle-en-us', NULL, 'Development, creation, and production of shows for the "Receitas Nestlé" Channel and Portal, from Nestlé Brazil. In 2019 and 2020, with over 50 episodes of various shows  delivered for the brand''s channel in different formats: reality, talk-show, documentary, culinary, etc. Among the formats, standout titles include: Chocolateria, Põe Cremosidade Nisso, Deu Ruim, Nutri Ajuda, Brasil Sabores Mil, Receitas de Final de Semana, Mais Vividas, and Escolhas Certas. Under the "Receitas Nestlé" umbrella, the brands Molico, Maggi, Garoto, Nutren, Nestlé Cream, Nestlé Oats, Leite Moça, Nescafé, and Nestlé Health Science were represented.', 'published', '{"order":48,"image":"https://bucket.farra.media/3.png","language":"enUS","slug":"poe-cremosidade-nisso-nestle","videos":"https://vimeo.com/732558375","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Production:","content":"Awake Film"},{"title":"Executive Production:","content":"Gui Vieira"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"7e35ea7d-1cba-4deb-9d25-e3044a32c29b","legacy_posttype":"jobs","post_thumbnail_id":"613"}', 1727795343000, 1727795343000, 1727795924607);
