INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (624, 15, NULL, NULL, 41, 'RAFI', 'rafi-pt-br', NULL, 'Após seis anos conquistando seu espaço em um dos cenários mais competitivos do stand-up mundial, Rafinha Bastos se prepara para gravar seu primeiro especial em inglês. Este documentário exclusivo oferece uma visão única dos bastidores dos três dias que antecedem a gravação, acompanhando o comediante em sua rotina pelos clubes de comédia dos EUA, enquanto reflete sobre sua trajetória — do Brasil ao tão esperado reconhecimento internacional.', 'published', '{"order":103,"image":"https://bucket.farra.media/RAFI.png","language":"ptbr","slug":"rafi","videos":"https://vimeo.com/1047243492","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Produ\u00e7\u00e3o:","content":"Farra"},{"title":"Dire\u00e7\u00e3o geral e Roteiro:","content":"Andr\u00e9 Brandt"},{"title":"Arte: ","content":"Beatriz Vidal"},{"title":"Produtores:","content":" Gui Vieira, Gui Cintra, Andr\u00e9 Brandt"},{"title":"Dire\u00e7\u00e3o de Fotografia:","content":"Alex Tavares"},{"title":"Produ\u00e7\u00e3o Executiva:","content":"Gui Vieira e Tayna Adam"},{"title":"Assistente de Produ\u00e7\u00e3o:","content":"Beatriz Fontada"},{"title":"Produ\u00e7\u00e3o:","content":"Juliana Hodas"},{"title":"Coordena\u00e7\u00e3o de P\u00f3s-produ\u00e7\u00e3o: ","content":"Fred Kesselring"},{"title":"Montagem:","content":"Dreiky F."},{"title":"Financeiro:","content":"Andressa Carrijo"},{"title":"Assistente de Montagem:","content":"Mike Prado"},{"title":"Colorista:","content":"Gabriel Ranzani"},{"title":"Produtora de som:","content":" Dream Box Produ\u00e7\u00f5es LTDA "},{"title":"Edi\u00e7\u00e3o de Som e Mixagem: ","content":"Guilherme Picolo e Tullio Zarpao"},{"title":"Finaliza\u00e7\u00e3o: ","content":"Fred Kesselring e Dreiky F."},{"title":"Legendas:\u00a0","content":"Dreiky Fraga"},{"title":"Produtor Executivo de P\u00f3s de Som: ","content":"Daniel Picolo "}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"9494ce47-96a4-4cc4-9a64-d004acb0b177","legacy_posttype":"jobs","post_thumbnail_id":"623"}', 1739777739000, 1739777739000, 1767788110177);
