INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (640, 15, NULL, NULL, 39, 'Release Luca | Disney+', 'release-luca-disney-en-us', NULL, 'Farra created, scripted and produced the pieces for the audiovisual campaign for the launch of the Disney/Pixar film Luca, which premiered exclusively on Disney+.

There were 4 distinct actions: a series of pieces and photos for publicity to the press with interviews and pieces for digital with the voice actors of the film Luis Miranda, Claudia Raia and Sophia Raia; a comedy skit with Luis, Claudia and Sophia; a live with Dani Calabresa for publicity on the film’s release day; a webseries with the Italian side of Dani Calabresa for dissemination in your networks.', 'published', '{"order":85,"image":"https://bucket.farra.media/lucca.png","language":"enUS","slug":"release-luca-disney","videos":["https://vimeo.com/558223465","https://vimeo.com/569538333","https://vimeo.com/569549244"],"videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Direction","content":"Gui Cintra"},{"title":"Executive Production","content":"Guilherme Vieira"},{"title":"Production Director","content":"Tarcila Villa"},{"title":"Writing","content":"Andr\u00e9 Brandt, Sergio Barbosa, Rodrigo Moura e Gui Cintra"},{"title":"Creation and Production","content":"Farra"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"291a2e91-db0f-4220-83a5-4294ace08df7","legacy_posttype":"jobs","post_thumbnail_id":"639"}', 1719707548000, 1719707548000, 1727792102592);
