INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (644, 15, NULL, NULL, 39, 'Releases | Netflix', 'releases-netflix-en-us', NULL, 'Launches of movies and series for Netflix with totally different plots and proposals: “El Camino”, a Breaking Bad movie with Maurício Meirelles included in the self-help group; “Elite”, with MC Kevinho, where we remade the party of the murdered man and included Kevinho in the deposition room with the delegate of the series; “Eu Resolvi Esperar”, campaign with Sandy to launch the second season of La Casa de Papel; “The Crown”, featuring Queen Elza Soares; and “Rome”, to promote Alfonso Cuarón’s Oscar-winning film.', 'published', '{"order":3,"image":"https://bucket.farra.media/lancamentos.png","language":"enUS","slug":"releases-netflix","videos":["https://vimeo.com/545673202","https://vimeo.com/605942768","https://vimeo.com/545673839","https://vimeo.com/545675365","https://vimeo.com/545665629"],"videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Production Coord.","content":"Guilherme Vieira"},{"title":"Producer","content":"Awake Film"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"64bcaf8d-a578-46d3-a28c-5f3fdc74c9e0","legacy_posttype":"jobs","post_thumbnail_id":"643"}', 1719706241000, 1719706241000, 1727799274908);
