INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (646, 15, NULL, NULL, 39, 'Resolvi Esperar com Sandy - La Casa de Papel |  Netflix', 'resolvi-esperar-com-sandy-la-casa-de-papel-netflix-en-us', NULL, 'Film and series releases for Netflix with completely different plots and proposals: “El Camino”, a Breaking Bad film with Maurício Meirelles included in the self-help group; “Elite”, with MC Kevinho, where we recreated the murdered man’s party and included Kevinho in the deposition room with the series’ police chief; “Eu Resolvi Esperar”, a campaign with Sandy for the launch of the second season of La Casa de Papel; “The Crown”, with the participation of Queen Elza Soares; and “Roma”, to promote Alfonso Cuarón’s Oscar-winning film.', 'published', '{"order":10,"image":"https://bucket.farra.media/D.png","language":"enUS","slug":"resolvi-esperar-com-sandy-la-casa-de-papel-netflix","videos":"https://vimeo.com/545673839","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Executive Producer:","content":"Gui Vieira "}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"15a366d1-cb59-4cfe-99a2-0041b921d0cd","legacy_posttype":"jobs","post_thumbnail_id":"645"}', 1727798928000, 1727798928000, 1727798963973);
