INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (648, 15, NULL, NULL, 41, 'Resolvi Esperar com Sandy - La Casa de Papel |  Netflix', 'resolvi-esperar-com-sandy-la-casa-de-papel-netflix-pt-br', NULL, 'Lançamentos de filmes e séries para Netflix com enredos e propostas totalmente distintas: “El Camino”, um filme de Breaking Bad com Maurício Meirelles inserido no grupo de autoajuda; “Elite”, com MC Kevinho, onde refizemos a festa do assassinado e incluímos Kevinho na sala de depoimento com a delegada da série; “Eu Resolvi Esperar”, campanha com Sandy para lançamento da segunda temporada de La Casa de Papel; “The Crown”, com participação da rainha Elza Soares; e “Roma”, para promoção do filme de Alfonso Cuarón, vencedor do Oscar.', 'published', '{"order":11,"image":"https://bucket.farra.media/D.png","language":"ptbr","slug":"resolvi-esperar-com-sandy-la-casa-de-papel-netflix","videos":"https://vimeo.com/545673839","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Produ\u00e7\u00e3o Executiva:","content":"Gui Vieira "}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"aade84b2-c0ab-4f08-b91e-4696ee3d3967","legacy_posttype":"jobs","post_thumbnail_id":"647"}', 1727311452704, 1727311452704, 1728385253240);
