INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (650, 15, NULL, NULL, 39, 'Rock in Rio | TIM', 'rock-in-rio-tim-en-us', NULL, 'For Rock in Rio 2022, the sponsor TIM set up an interactive stand at the premises. The audience could touch the screens and interact with the celebrities Iza and Marcos Mion. Farra was the production company responsible for capturing all these videos in a Chroma Key shoot. 

On the same day, we also shot the whole digital campaign for TIM’s social media with Marcos Mion’s presence, adding up to 160 videos for the entirety of the event.', 'published', '{"order":88,"image":"https://bucket.farra.media/mion.png","language":"enUS","slug":"rock-in-rio-tim","videos":"https://vimeo.com/788696697","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Direction","content":"Gui Cintra"},{"title":"Executive Producer","content":"Gui Vieira e Tarcila Villa"},{"title":"Production","content":"Farra"},{"title":"","content":""}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"2f7527dc-2632-4d10-a301-a48bd2019a64","legacy_posttype":"jobs","post_thumbnail_id":"649"}', 1719708542000, 1719708542000, 1727791865426);
