INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (652, 15, NULL, NULL, 41, 'Rock in Rio | TIM', 'rock-in-rio-tim-pt-br', NULL, 'Para o Rock in Rio 2022 a patrocinadora TIM montou um stand interativo no evento. O público podia tocar nas telas e trocar com os talentos Iza e Marcos Mion. A Farra foi a produtora responsável pelas captações em vídeo dessa interação, em uma diária em estúdio Chroma Key com artistas. Nesse mesmo dia, além das interações fizemos toda a campanha digital para as redes sociais de Tim com a interação de Marcos Mion, realizando 160 vídeos para todos os dias do evento.', 'published', '{"order":89,"image":"https://bucket.farra.media/mion.png","language":"ptbr","slug":"rock-in-rio-tim","videos":"https://vimeo.com/788696697","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Dire\u00e7\u00e3o","content":"Gui Cintra"},{"title":"Produ\u00e7\u00e3o Executiva","content":"Gui Vieira e Tarcila Villa"},{"title":"Roteiro","content":"Farra"},{"title":"Ag\u00eancia Cria\u00e7\u00e3o","content":"BETC"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"40254b08-3be8-448c-8349-c3b1969b10a8","legacy_posttype":"jobs","post_thumbnail_id":"651"}', 1716465396000, 1716465396000, 1726844891781);
