INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (658, 15, NULL, NULL, 39, 'Seus momentos sua vida | Canon', 'seus-momentos-sua-vida-canon-en-us', NULL, 'Project for a tutorial on basic Canon lenses and the T3i camera. To create something beyond the conventional, we went abroad to show how the equipment is used in real life. Production intelligence in conducting the work, a skilled and lean team brought to a low-budget project the vision of four different locations in our country: Jalapão, Rio de Janeiro, Itatiaia National Park and Manaus. The result was 6 tutorial videos and a hero video for the campaign.', 'published', '{"order":7,"image":"https://bucket.farra.media/canon.png","language":"enUS","slug":"seus-momentos-sua-vida-canon","videos":["https://vimeo.com/589430081",""],"videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Executive Producer:","content":"Guilherme Vieira"},{"title":"Production:","content":"Awake Film"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"3b28c38a-a065-4326-bcee-aaa232e69acb","legacy_posttype":"jobs","post_thumbnail_id":"657"}', 1727799075000, 1727799075000, 1727799123156);
