INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (660, 15, NULL, NULL, 41, 'Seus momentos sua vida | Canon', 'seus-momentos-sua-vida-canon-pt-br', NULL, 'Projeto para um tutorial de lentes básicas da Canon e câmera T3i. Para criar algo além do convencional, fomos para externa mostrar o uso do equipamento na realidade. Inteligência de produção na condução do trabalho, equipe capacitada e enxuta trouxeram para um projeto low budget a visão de quatro locações distintas em nosso país, Jalapão, Rio de Janeiro, Parque Nacional de Itatiaia e Manaus. O resultado foram 6 vídeos tutoriais e um vídeo hero da campanha.', 'published', '{"order":8,"image":"https://bucket.farra.media/canon.png","language":"ptbr","slug":"seus-momentos-sua-vida-canon","videos":["https://vimeo.com/589430081",""],"videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Produ\u00e7\u00e3o e Produ\u00e7\u00e3o Executiva","content":"Guilherme Vieira"},{"title":"Produtora","content":"Awake Film"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"a137dccb-401f-47eb-94a4-9c006bb220ce","legacy_posttype":"jobs","images":"[\"https://bucket.farra.media/canon_0003_Camada-1.png\",\"https://bucket.farra.media/canon_0002_Camada-2.png\",\"https://bucket.farra.media/canon_0000_Camada-4.png\"]","post_thumbnail_id":"659"}', 1716419732000, 1716419732000, 1727312509214);
