INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (670, 15, NULL, NULL, 39, 'Supositório | Spotify', 'supositorio-spotify-en-us', NULL, 'Presented by André Brandt, Suppository is a space to imagine other realities that would be possible if something different had happened in history. Along with him, always two celebrities embark on these absurd assumptions that have surely crossed their minds, or if not, will pass now. Suppository is an Original Spotify podcast produced by Farra. New episodes on Mondays.', 'published', '{"order":69,"image":"https://bucket.farra.media/supositorio.png","language":"enUS","slug":"supositorio-spotify","videos":"https://vimeo.com/744341142","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Direction","content":"Andr\u00e9 Brandt"},{"title":"Writing","content":"Ste Marques"},{"title":"Editing","content":"Lucas Ara\u00fajo"},{"title":"Project Management","content":"Rosa Taques"},{"title":"Design","content":"Beatriz Vidal"},{"title":"Production","content":"Farra"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"11ed8fdc-919c-405f-a68d-eced09c3e078","legacy_posttype":"jobs","post_thumbnail_id":"669"}', 1719708819000, 1719708819000, 1727793224803);
