INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (672, 15, NULL, NULL, 41, 'Supositório | Spotify', 'supositorio-spotify-pt-br', NULL, 'Apresentado por André Brandt, Supositório é um espaço para imaginar outras realidades que seriam possíveis caso algo de diferente tivesse acontecido na história. Junto com ele, sempre duas celebridades embarcam nessas suposições absurdas que com certeza já passaram pela sua cabeça, ou se não, vão passar agora. Supositório é um podcast Original Spotify produzido pela Farra. Episódios novos às segundas-feiras.', 'published', '{"order":70,"image":"https://bucket.farra.media/supositorio.png","language":"ptbr","slug":"supositorio-spotify","videos":"https://vimeo.com/744341142","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Dire\u00e7\u00e3o","content":"Andr\u00e9 Brandt"},{"title":"Roteiro","content":"Ste Marques"},{"title":"Edi\u00e7\u00e3o","content":"Lucas Ara\u00fajo"},{"title":"Gest\u00e3o de Projeto","content":"Rosa Taques"},{"title":"Arte","content":"Beatriz Vidal"},{"title":"Produ\u00e7\u00e3o","content":"Farra"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"2416c4ee-6309-42d3-9442-3bfa0b4e422f","legacy_posttype":"jobs","post_thumbnail_id":"671"}', 1716478736000, 1716478736000, 1727185224463);
