INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (674, 15, NULL, NULL, 41, 'Tati Folia 2025', 'tati-folia-2025-pt-br', NULL, 'Prepare-se para viver os bastidores do carnaval de uma maneira única: o TATI FOLIA, reality produzido pela FARRA, com direção de Hugo Moura e roteiro de Gui Cintra, chegou para mostrar os desafios, perrengues e toda a dedicação de Tati Barbieri, primeira musa e madrinha de comissão de frente do Salgueiro! 👑❤️ Para quem ainda não assistiu, vale conferir lá no canal do YouTube @FamLifeReality', 'published', '{"order":98,"image":"https://bucket.farra.media/tttt.png","language":"ptbr","slug":"tati-folia-2025","videos":"https://vimeo.com/1047247244","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Produ\u00e7\u00e3o:","content":"Farra"},{"title":"Produ\u00e7\u00e3o Executiva:","content":"Gui Vieira "},{"title":"Dire\u00e7\u00e3o:","content":"Hugo Moura"},{"title":"Montagem e Edi\u00e7\u00e3o:","content":" Luis Guilherme"},{"title":"P\u00f3s Produ\u00e7\u00e3o:","content":"Fred Kesselring"},{"title":"Arte:","content":"Beatriz Vidal "},{"title":"Redes Sociais:","content":"Patricia Vergilli"},{"title":"Dire\u00e7\u00e3o de Produ\u00e7\u00e3o: ","content":"Ju Hodas "}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"e8c13b21-b194-4239-9f36-ca1bab14853a","legacy_posttype":"jobs","images":"[\"https://bucket.farra.media/tttt.png\"]","post_thumbnail_id":"673"}', 1739790000000, 1739790000000, 1742303427532);
