INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (680, 15, NULL, NULL, 39, 'The Crown com Elza Soares | Netflix', 'the-crown-com-elza-soares-netflix-en-us', NULL, 'Film and series releases for Netflix with completely different plots and proposals: “El Camino”, a Breaking Bad film with Maurício Meirelles included in the self-help group; “Elite”, with MC Kevinho, where we recreated the murdered man’s party and included Kevinho in the deposition room with the series’ police chief; “Eu Resolvi Esperar”, a campaign with Sandy for the launch of the second season of La Casa de Papel; “The Crown”, with the participation of Queen Elza Soares; and “Roma”, to promote Alfonso Cuarón’s Oscar-winning film.', 'published', '{"order":14,"image":"https://bucket.farra.media/f.png","language":"enUS","slug":"the-crown-com-elza-soares-netflix","videos":"https://vimeo.com/545675365","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Executive Producer:","content":"Gui Vieira "}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"18521bd0-3057-429c-bbb8-e0fb04b2e195","legacy_posttype":"jobs","post_thumbnail_id":"679"}', 1727798669000, 1727798669000, 1727798711237);
