INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (682, 15, NULL, NULL, 41, 'The Crown com Elza Soares | Netflix', 'the-crown-com-elza-soares-netflix-pt-br', NULL, 'Lançamentos de filmes e séries para Netflix com enredos e propostas totalmente distintas: “El Camino”, um filme de Breaking Bad com Maurício Meirelles inserido no grupo de autoajuda; “Elite”, com MC Kevinho, onde refizemos a festa do assassinado e incluímos Kevinho na sala de depoimento com a delegada da série; “Eu Resolvi Esperar”, campanha com Sandy para lançamento da segunda temporada de La Casa de Papel; “The Crown”, com participação da rainha Elza Soares; e “Roma”, para promoção do filme de Alfonso Cuarón, vencedor do Oscar.', 'published', '{"order":14,"image":"https://bucket.farra.media/f.png","language":"ptbr","slug":"the-crown-com-elza-soares-netflix","videos":"https://vimeo.com/545675365","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Produ\u00e7\u00e3o Executiva:","content":"Gui Vieira "}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"e802b9c8-0e2e-4912-aa01-3808e246ab0e","legacy_posttype":"jobs","post_thumbnail_id":"681"}', 1727311994586, 1727311994586, 1728385283357);
