INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (684, 15, NULL, NULL, 39, 'The Power of Choice | Rennova', 'the-power-of-choice-rennova-en-us', NULL, 'Farra was the production company responsible for the script and production of the advertising piece for the Rennova brand, a line of products for injectable aesthetic procedures that emphasizes the importance of choosing well-being. And this production had the participation of ambassadors Giovanna Antonelli and Deborah Secco! It was an ambitious and challenging project. Farra, in partnership and synergy with Rennova, created and produced this film, which was recorded in Rio de Janeiro and adapted for both TV and online broadcasting, in addition to content for the brand''s Landing Page, providing an engaging experience for Rennova''s target audience.', 'published', '{"order":94,"image":"https://bucket.farra.media/rennova-1.png","language":"enUS","slug":"the-power-of-choice-rennova","videos":"https://vimeo.com/869568669","videosHome":["https://vimeo.com/869568669"],"videosHomeOrder":null,"fichaTecnica":[{"title":"Creation:","content":"Andr\u00e9 Brandt, S\u00e9rgio Barbosa e Rodrigo Moura"},{"title":"Direction:","content":"Hugo Moura"},{"title":"Production Direction:","content":"Juliana Hodas"},{"title":"Executive Production:","content":"Gui Vieira e Tayna Adam"},{"title":"Production:","content":"Farra"},{"title":"Editor:","content":"Lucas Araujo"},{"title":"Post-production Coordination:","content":"Fred Kesselring"},{"title":"Production Direction:","content":"Ju Hodas"},{"title":"Executive Production Assistance:","content":"Beatriz Fontana"}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"123f49f6-8786-48d1-8cdd-8f6416de2de2","legacy_posttype":"jobs","post_thumbnail_id":"683"}', 1716477546000, 1716477546000, 1727799514035);
