INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (686, 15, NULL, NULL, 41, 'Toca Revela - O Reality | UOL', 'toca-revela-o-reality-uol-pt-br', NULL, 'Toca Revela é o novo reality show do UOL para divulgar um novo talento musical. A Farra é a produtora responsável pela criação, roteiro e produção do projeto em conjunto com o time do UOL TOCA, e direção de Gui Cintra Serão 10 episódios que começam a partir do próximo mês com um prêmio final de gravação profissional e mixagem com um mestre do mercado @dudumarote e distribuição do selo Alta Fonte Brasil.', 'published', '{"order":105,"image":"https://bucket.farra.media/toca.png","language":"ptbr","slug":"toca-revela-o-reality-uol","videos":"https://vimeo.com/1040125428","videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Produ\u00e7\u00e3o Executiva:","content":"Gui Vieira e Tayna Adam"},{"title":"Dire\u00e7\u00e3o:","content":"Gui Cintra"},{"title":"Produ\u00e7\u00e3o:","content":"Farra"},{"title":"Dire\u00e7\u00e3o de Arte:","content":"Beatriz Vidal"},{"title":"Edi\u00e7\u00e3o: ","content":"Mike Prado"},{"title":"Dire\u00e7\u00e3o de Produ\u00e7\u00e3o:","content":""}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"af3c962f-c4b4-4187-a02d-ea2fcb651663","legacy_posttype":"jobs","post_thumbnail_id":"685"}', 1736169965000, 1736169965000, 1740011831792);
