INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (692, 15, NULL, NULL, 39, 'Truco Masters', 'truco-masters-en-us', NULL, 'Idealizada por Gui Vieira e produzida pela Farra, a primeira edição do campeonato transformou o jogo clássico de truco em um espetáculo digital de alcance nacional. O evento reuniu influenciadores, artistas e jornalistas em uma competição transmitida simultaneamente nos canais do Truco Masters, Gaules e PodPah, com narração de Toboco e comentários de Marcus Cirillo. Com estrutura de show de alto padrão, com mais de 20 câmeras e uma audiência de quase 10 mil aparelhos conectados de forma simultâneas, o Truco Masters apresentou o jogo popular em um formato moderno e imersivo, unindo a tradição das cartas ao universo gamer e do streaming. A dupla campeã foi Os Abençoados, composta por Padre Caio e Vô Tonho, que conquistou o prêmio de R$ 40.000,00, enquanto a dupla vice-campeã, Trucocaia, levou R$ 10.000,00.', 'published', '{"order":108,"image":"https://bucket.farra.media/truco- Farra.png","language":"enUS","slug":"truco-masters","videos":["https://vimeo.com/1148042752",""],"videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Ag\u00eancia e Produ\u00e7\u00e3o","content":"Farra"},{"title":"Reda\u00e7\u00e3o:","content":"Rodrigo Moura"},{"title":"Cria\u00e7\u00e3o: ","content":"Gui Vieira"},{"title":"Produ\u00e7\u00e3o Executiva:","content":"Gui Vieira e Juliana Hodas"},{"title":"Dire\u00e7\u00e3o de Produ\u00e7\u00e3o:","content":"Juliana Hodas"},{"title":"Assist\u00eancia de Dire\u00e7\u00e3o:","content":"Bruna Leonardi"},{"title":"Dire\u00e7\u00e3o:","content":"Marcelo Mauad"},{"title":"Dire\u00e7\u00e3o de Arte:","content":"Beatriz Vidal"},{"title":"Produ\u00e7\u00e3o de Arte:","content":"Jenny Shauff"},{"title":"Motion:","content":"Serginho Dimi"},{"title":"","content":""},{"title":"","content":""},{"title":"Coordena\u00e7\u00e3o de P\u00f3s-produ\u00e7\u00e3o:","content":"Lais Paix\u00e3o"},{"title":"Edi\u00e7\u00e3o:","content":"Mike Prado"},{"title":"","content":""},{"title":"","content":""},{"title":"","content":""},{"title":"","content":""},{"title":"","content":""},{"title":"","content":""}],"socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"ce8e3773-0412-4968-9259-04342aa73cc9","legacy_posttype":"jobs","post_thumbnail_id":"691"}', 1713531317000, 1713531317000, 1767787679587);
