INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (694, 15, NULL, NULL, 41, 'Truco Masters', 'truco-masters-pt-br', NULL, 'Idealizada por Gui Vieira e produzida pela Farra, a primeira edição do campeonato transformou o jogo clássico de truco em um espetáculo digital de alcance nacional. O evento reuniu influenciadores, artistas e jornalistas em uma competição transmitida simultaneamente nos canais do Truco Masters, Gaules e PodPah, com narração de Toboco e comentários de Marcus Cirillo. Com estrutura de show de alto padrão, com mais de 20 câmeras e uma audiência de quase 10 mil aparelhos conectados de forma simultâneas, o Truco Masters apresentou o jogo popular em um formato moderno e imersivo, unindo a tradição das cartas ao universo gamer e do streaming. A dupla campeã foi Os Abençoados, composta por Padre Caio e Vô Tonho, que conquistou o prêmio de R$ 40.000,00, enquanto a dupla vice-campeã, Trucocaia, levou R$ 10.000,00.', 'published', '{"order":114,"image":"https://bucket.farra.media/truco- Farra.png","language":"ptbr","slug":"truco-masters","videos":["https://vimeo.com/1148042752",""],"videosHome":null,"videosHomeOrder":null,"fichaTecnica":[{"title":"Agência e Produção","content":"Farra"},{"title":"Redação:","content":"Rodrigo Moura"},{"title":"Criação: ","content":"Gui Vieira"},{"title":"Produção Executiva:","content":"Gui Vieira e Juliana Hodas"},{"title":"Direção de Produção:","content":"Juliana Hodas"},{"title":"Assistência de Direção:","content":"Bruna Leonardi"},{"title":"Direção:","content":"Marcelo Mauad"},{"title":"Direção de Arte:","content":"Beatriz Vidal"},{"title":"Produção de Arte:","content":"Jenny Shauff"},{"title":"Motion:","content":"Serginho Dimi"},{"title":"Social Media Manager:","content":"Patrícia Vergili"},{"title":"Coordenação de Pós-produção:","content":"Lais Paixão"},{"title":"Edição:","content":"Mike P