INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (1146, 2, NULL, 'fs9SN8qiF2JCfORn2tkWj3DTiA9qHVhe', 41, 'A Farra', 'a-farra', 'ENTRETENIMENTO PARA TODAS AS MÍDIASOs sócios André Brandt, Gui Vieira e Gui Cintra acumulam experiências em roteiro, criação, direção, produção e produção executiva de conteúdo e publicidade nos mais renomados players do mercado, como TV Globo, Netfl', '<h3 data-level="3">ENTRETENIMENTO PARA TODAS AS MÍDIAS</h3><hr><p>Os sócios André Brandt, Gui Vieira e Gui Cintra acumulam experiências em roteiro, criação, direção, produção e produção executiva de conteúdo e publicidade nos mais renomados players do mercado, como TV Globo, Netflix, Disney, Instagram, Viacom, WarnerBros Discovery, Spotify, RecordTV, Bandeirantes, Globoplay, Amazon Prime Video, ESPN, GNT e Multishow. Soma-se a essa bagagem um time fixo de profissionais de ofícios plurais, garantindo à Farra a entrega de serviços na lógica end-to-end.</p><p></p>', 'published', '{"order":"","post_thumbnail_id":"1145"}', NULL, 1779395388082, 1779466873504);
