INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (1211, 15, NULL, NULL, 41, 'CAMPANHA DIGITAL: ABERTO AO PÚBLICO Temporada 1 e 2 | TVGlobo', 'campanha-digital-aberto-ao-publico-temporada-1-e-2-tvglobo-pt-br', NULL, 'Para as duas temporadas do programa, a Farra desenvolveu uma estratégia robusta de conteúdo para redes sociais, com 169 peças digitais.
