INSERT OR REPLACE INTO edp_posts (id, post_type_id, parent_id, author_id, id_locale_code, title, slug, excerpt, body, status, meta_values, published_at, created_at, updated_at) VALUES (1231, 15, NULL, NULL, 39, 'CONTROLE DE QUALIDADE com REGINA VOLPATO | PARAMOUNT +', 'controle-de-qualidade-com-regina-volpato-paramount-en-us', NULL, 'Farra created and produced a new campaign for Paramount+, starring Regina Volpato, with the aim of promoting the streaming service''s drama series – without neglecting the good humor that is a characteristic of the Brazilian people. Directed by Gui Cintra and following the concept "Addicted to a good drama," the proposal is to highlight that the platform has become a benchmark when it comes to offering a strong catalog of the genre to the Brazilian audience, which, like Paramount+, is passionate about a good drama.', 'published', '{"videos":"https://vimeo.com/1068297412","videosHome":null,"videosHomeOrder":null,"order":97,"fichaTecnica":[{"title":"Production:","content":"Farra"},{"title":"Direction: ","content":"Gui Cintra"}],"language":"enUS","socialMedia":null,"reel":null,"posttype":"jobs","legacy_id":"88db2fa3-fb7a-4ef6-8aaf-d44b1a3fcb87","legacy_posttype":"jobs","slug":"controle-de-qualidade-com-regina-volpato-paramount","image":"https://bucket.farra.media/REGUN.png","post_thumbnail_id":"1230"}', 1776364254000, 1776364254000, 1776364316015);
